Assets::~Assets() {
    // Check if the Assets object owns a valid memory-mapped partition handle
    if (mmap_handle_ != 0) {
        // Unmap the memory-mapped partition if a valid handle exists
        esp_partition_unmap(mmap_handle_);

        // Ensure no further access to the unmapped memory region
        // Set pointers to nullptr to prevent dangling pointer access
        mmap_root_ = nullptr;
        mmap_handle_ = 0;
    }
}

uint16_t CalculateChecksum(const char *buffer, uint32_t size) {
    // Validate input parameters
    if (buffer == nullptr) {
        return 0;
    }

    // Initialize checksum to 0
    uint32_t checksum = 0;

    // Sum all byte values in the buffer
    for (uint32_t i = 0; i < size; ++i) {
        checksum += static_cast<uint8_t>(buffer[i]);
    }

    // Apply 16-bit mask to ensure result fits within 16 bits
    return static_cast<uint16_t>(checksum & 0xFFFF);
}

