bool Assets::InitializePartition() {
    ESP_LOGI(TAG, "Initializing assets partition");

    // Step 1: Validate that the assets partition exists in flash memory and has sufficient space
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, 
        ESP_PARTITION_SUBTYPE_DATA_UNDEFINED, 
        "assets"
    );

    if (partition == nullptr) {
        ESP_LOGE(TAG, "Assets partition not found");
        partition_valid_ = false;
        checksum_valid_ = false;
        return false;
    }

    partition_ = partition;

    // Check if partition has sufficient space (at least 4KB for minimum structure)
    if (partition_->size < 4096) {
        ESP_LOGE(TAG, "Assets partition too small: %lu bytes", partition_->size);
        partition_valid_ = false;
        checksum_valid_ = false;
        return false;
    }

    partition_valid_ = true;

    // Step 2: Perform checksum verification on the partition data to ensure integrity
    // Map the partition into memory for access
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, 
                                       ESP_PARTITION_MMAP_DATA, 
                                       (const void**)&mmap_root_, 
                                       &mmap_handle_);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        checksum_valid_ = false;
        return false;
    }

    // Verify checksum - assuming first 4 bytes contain the checksum
    if (partition_->size < sizeof(uint32_t)) {
        ESP_LOGE(TAG, "Partition too small for checksum");
        checksum_valid_ = false;
        return false;
    }

    uint32_t stored_checksum = *(uint32_t*)mmap_root_;
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_ + sizeof(uint32_t), 
                                                     partition_->size - sizeof(uint32_t));

    if (stored_checksum != calculated_checksum) {
        ESP_LOGE(TAG, "Checksum mismatch: stored=0x%08x, calculated=0x%08x", 
                 stored_checksum, calculated_checksum);
        checksum_valid_ = false;
        return false;
    }

    checksum_valid_ = true;

    // Step 3: Map the validated partition into memory for direct access
    // (Already done above with esp_partition_mmap)

    // Step 4: Build an in-memory index of all assets including their offsets and sizes for fast lookup
    assets_.clear();

    // Assuming the partition structure starts with a header containing asset count
    // and then asset entries with name, offset, and size
    const char* data_ptr = mmap_root_ + sizeof(uint32_t);  // Skip checksum
    size_t offset = sizeof(uint32_t);

    // Read asset count (assuming it's at the start after checksum)
    if (offset + sizeof(uint32_t) > partition_->size) {
        ESP_LOGW(TAG, "Invalid partition structure - insufficient data for asset count");
        return true;  // Still valid but no assets found
    }

    uint32_t asset_count = *(uint32_t*)data_ptr;
    offset += sizeof(uint32_t);
    data_ptr += sizeof(uint32_t);

    // Parse each asset entry
    for (uint32_t i = 0; i < asset_count && offset < partition_->size; ++i) {
        // Read asset name length
        if (offset + sizeof(uint32_t) > partition_->size) {
            ESP_LOGW(TAG, "Invalid partition structure - insufficient data for asset name length");
            break;
        }

        uint32_t name_len = *(uint32_t*)data_ptr;
        offset += sizeof(uint32_t);
        data_ptr += sizeof(uint32_t);

        // Read asset name
        if (offset + name_len > partition_->size) {
            ESP_LOGW(TAG, "Invalid partition structure - asset name exceeds partition bounds");
            break;
        }

        std::string name(data_ptr, name_len);
        offset += name_len;
        data_ptr += name_len;

        // Read asset offset
        if (offset + sizeof(size_t) > partition_->size) {
            ESP_LOGW(TAG, "Invalid partition structure - insufficient data for asset offset");
            break;
        }

        size_t asset_offset = *(size_t*)data_ptr;
        offset += sizeof(size_t);
        data_ptr += sizeof(size_t);

        // Read asset size
        if (offset + sizeof(size_t) > partition_->size) {
            ESP_LOGW(TAG, "Invalid partition structure - insufficient data for asset size");
            break;
        }

        size_t asset_size = *(size_t*)data_ptr;
        offset += sizeof(size_t);
        data_ptr += sizeof(size_t);

        // Store in our asset map
        assets_[name] = {asset_size, asset_offset};

        ESP_LOGD(TAG, "Indexed asset '%s' at offset %zu, size %zu", 
                 name.c_str(), asset_offset, asset_size);
    }

    ESP_LOGI(TAG, "Successfully initialized assets partition with %zu assets", assets_.size());
    return true;
}

