bool Assets::Download(const std::string& url, std::function<void(int progress, size_t speed)> progress_callback) {
    try {
        // Step 1: Initialize network connection and HTTP request to fetch asset from URL
        NetworkInterface* network = NetworkInterface::getInstance();
        if (!network->connect()) {
            return false;
        }

        HttpResponse response = network->get(url);
        if (response.getStatusCode() != 200) {
            network->disconnect();
            return false;
        }

        size_t content_length = response.getContentLength();
        if (content_length == 0) {
            network->disconnect();
            return false;
        }

        // Step 2: Validate downloaded content size against available flash partition space
        FlashMemoryManager* flash_manager = FlashMemoryManager::getInstance();
        size_t available_space = flash_manager->getAvailableSpace();
        if (content_length > available_space) {
            network->disconnect();
            return false;
        }

        // Step 3: Erase flash memory sector(s) before writing new asset data
        size_t sector_size = flash_manager->getSectorSize();
        size_t sectors_to_erase = (content_length + sector_size - 1) / sector_size;

        for (size_t i = 0; i < sectors_to_erase; ++i) {
            if (!flash_manager->eraseSector(i)) {
                network->disconnect();
                return false;
            }
        }

        // Step 4: Write downloaded asset data to flash memory in chunks with progress updates
        const char* data = response.getBody().data();
        size_t total_written = 0;
        size_t chunk_size = 1024; // 1KB chunks

        while (total_written < content_length) {
            size_t remaining = content_length - total_written;
            size_t write_size = (remaining < chunk_size) ? remaining : chunk_size;

            if (!flash_manager->writeData(total_written, data + total_written, write_size)) {
                network->disconnect();
                return false;
            }

            total_written += write_size;

            // Calculate progress percentage
            int progress = static_cast<int>((total_written * 100) / content_length);

            // Calculate speed (simplified - actual implementation would measure time)
            size_t speed = write_size; // Placeholder for actual speed calculation

            // Report progress
            if (progress_callback) {
                progress_callback(progress, speed);
            }
        }

        // Step 5: Handle errors and cleanup resources on failed download or write operations
        // All error handling is done through early returns above

        // Step 6: Return completion status after successful asset download and storage
        network->disconnect();
        return true;

    } catch (const std::exception& e) {
        // Handle any unexpected exceptions
        return false;
    }
}

bool Assets::GetAssetData(const std::string& asset_name, void*& data_ptr, size_t& data_size) {
    // Step 1: Validate the input asset name and ensure it is not empty
    if (asset_name.empty()) {
        return false;
    }

    // Step 2: Locate the asset in the preloaded memory buffer using the asset name
    // Assuming there's a map or similar structure storing assets by name
    auto asset_it = assets_map_.find(asset_name);
    if (asset_it == assets_map_.end()) {
        return false;
    }

    // Get the asset data pointer and size from the map entry
    const AssetHeader* header = static_cast<const AssetHeader*>(asset_it->second.data);
    data_ptr = const_cast<void*>(static_cast<const void*>(header + 1)); // Skip header
    data_size = asset_it->second.size - sizeof(AssetHeader); // Exclude header size

    // Step 3: Verify the integrity of the asset by checking its magic number header
    // Assuming AssetHeader contains a magic_number field
    if (header->magic_number != ASSET_MAGIC_NUMBER) {
