bool DeviceStateMachine::IsValidTransition(DeviceState current_state, DeviceState target_state) const {
    // Handle self-transition (same state to same state)
    if (current_state == target_state) {
        return true;  // Self-transitions are generally allowed
    }

    // Define valid state transitions based on common device state machine patterns
    switch (current_state) {
        case DEVICE_STATE_OFF:
            // From OFF, can only transition to ON
            return target_state == DEVICE_STATE_ON;

        case DEVICE_STATE_ON:
            // From ON, can transition to STANDBY or ERROR
            return (target_state == DEVICE_STATE_STANDBY || 
                    target_state == DEVICE_STATE_ERROR);

        case DEVICE_STATE_STANDBY:
            // From STANDBY, can transition to ON or ERROR
            return (target_state == DEVICE_STATE_ON || 
                    target_state == DEVICE_STATE_ERROR);

        case DEVICE_STATE_ERROR:
            // From ERROR, can only transition back to OFF or STANDBY
            return (target_state == DEVICE_STATE_OFF || 
                    target_state == DEVICE_STATE_STANDBY);

        default:
            // Any other transition is invalid
            return false;
    }
}

