    // Step 1: Validate the requested state transition against predefined rules
    if (!IsTransitionAllowed(current_state_, new_state)) {
        // Log invalid transition attempt or handle error appropriately
        return;
    }

    // Step 2: Execute the state change if validation passes
    DeviceState previous_state = current_state_;
    current_state_ = new_state;

    // Step 3: Notify all registered observers of the state change
    NotifyObservers(previous_state, current_state_);
}

