std::string Ota::GetCheckVersionUrl() {
    // Try to get the OTA version check URL from settings
    Settings settings("ota", true);
    std::string url = settings.GetString("check_version_url");

    // Validate if the retrieved URL is empty or invalid
    if (url.empty() || url.length() < 10) {
        // Fall back to default configuration value
        // Using a reasonable default URL format
        url = "https://ota.example.com/check-version";
        ESP_LOGW(TAG, "Using default OTA version check URL: %s", url.c_str());
    }

    // Additional validation - ensure it starts with http:// or https://
    if (url.find("http://") != 0 && url.find("https://") != 0) {
        // If it doesn't start with a protocol, use default
        url = "https://ota.example.com/check-version";
        ESP_LOGW(TAG, "Invalid URL format, using default: %s", url.c_str());
    }

    return url;
}

