std::unique_ptr<HttpClient> Ota::SetupHttp() {
    // Initialize HTTP client configuration with default settings
    auto http = std::make_unique<HttpClient>();

    // Set device identification and user agent headers
    auto& board = Board::GetInstance();
    std::string device_id = board.GetDeviceId();
    http->SetHeader("X-Device-ID", device_id);

    std::string user_agent = "ESP32-OTA-Agent/1.0";
    http->SetHeader("User-Agent", user_agent);

    // Add language and content type headers for compatibility
    http->SetHeader("Accept-Language", "en-US,en;q=0.9");
    http->SetHeader("Content-Type", "application/json");

    // Conditionally include serial number header based on provisioning status
    if (board.IsProvisioned()) {
        std::string serial_number = board.GetSerialNumber();
        http->SetHeader("X-Serial-Number", serial_number);
    }

    // Return configured HTTP client instance for OTA communication
    return http;
}

