esp_err_t Ota::CheckVersion() {
    // Initialize network connection and prepare HTTP request
    HttpClient http_client;
    esp_err_t err = http_client.Init();
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return err;
    }

    // Prepare URL for version check
    std::string url = GetCheckVersionUrl();
    if (url.empty()) {
        ESP_LOGE(TAG, "OTA server URL is empty");
        return ESP_ERR_INVALID_ARG;
    }

    // Send HTTP request to remote OTA server for version check
    HttpResponse response;
    err = http_client.Get(url, &response);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to send HTTP request to OTA server: %s", esp_err_to_name(err));
        return err;
    }

    // Parse JSON response from OTA server for version info
    cJSON* json_root = cJSON_Parse(response.body.c_str());
    if (json_root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse JSON response from OTA server");
        return ESP_ERR_INVALID_RESPONSE;
    }

    // Extract firmware version and metadata
    const char* remote_version = cJSON_GetObjectItem(json_root, "version")->valuestring;
    if (remote_version == nullptr) {
        ESP_LOGE(TAG, "Remote version not found in JSON response");
        cJSON_Delete(json_root);
        return ESP_ERR_INVALID_RESPONSE;
    }

    // Compare local and remote firmware versions for update decision
    int version_cmp = CompareVersions(GetCurrentVersion(), remote_version);
    if (version_cmp > 0) {
        // Remote version is newer
        SetNewVersionAvailable(true);
        SetFirmwareVersion(remote_version);
        SetFirmwareUrl(cJSON_GetObjectItem(json_root, "url")->valuestring);

        // Handle activation data if present
        cJSON* activation_data = cJSON_GetObjectItem(json_root, "activation");
        if (activation_data != nullptr) {
            const char* activation_code = cJSON_GetObjectItem(activation_data, "code")->valuestring;
            const char* activation_message = cJSON_GetObjectItem(activation_data, "message")->valuestring;

            if (activation_code != nullptr) {
                SetActivationCode(activation_code);
            }
            if (activation_message != nullptr) {
                SetActivationMessage(activation_message);
            }
        }

        // Handle MQTT configuration updates if present
        cJSON* mqtt_config = cJSON_GetObjectItem(json_root, "mqtt");
        if (mqtt_config != nullptr) {
            const char* mqtt_server = cJSON_GetObjectItem(mqtt_config, "server")->valuestring;
            int mqtt_port = cJSON_GetObjectItem(mqtt_config, "port")->valueint;
            const char* mqtt_username = cJSON_GetObjectItem(mqtt_config, "username")->valuestring;
            const char* mqtt_password = cJSON_GetObjectItem(mqtt_config, "password")->valuestring;

            if (mqtt_server != nullptr) {
                SetMqttServer(mqtt_server);
            }
            if (mqtt_username != nullptr && mqtt_password != nullptr) {
                SetMqttCredentials(mqtt_username, mqtt_password);
            }
            SetMqttPort(mqtt_port);
        }
    } else if (version_cmp < 0) {
        // Local version is newer (shouldn't happen but handle gracefully)
        ESP_LOGW(TAG, "Local version is newer than remote version");
    }

    // Clean up JSON parser
    cJSON_Delete(json_root);

    // Log OTA version check outcome and notify system
    ESP_LOGI(TAG, "OTA version check completed. Local: %s, Remote: %s, Update available: %s",
             GetCurrentVersion().c_str(), 
             remote_version, 
             version_cmp > 0 ? "true" : "false");

    // Return error code after OTA version check completion
    return ESP_OK;
}

