void Ota::MarkCurrentVersionValid() {
    ESP_LOGD(TAG, "Starting firmware version validation process");

    // Get current firmware partition information
    esp_partition_t current_partition;
    const esp_partition_t* running_partition = esp_ota_get_running_partition();

    if (running_partition == nullptr) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    // Check if this is the factory partition - skip validation for factory partition
    if (running_partition->subtype == ESP_PARTITION_SUBTYPE_APP_FACTORY) {
        ESP_LOGI(TAG, "Skipping validation for factory partition");
        return;
    }

    // Check if current partition is in pending verification state
    // This typically involves checking partition metadata or flags
    esp_ota_handle_t ota_handle;
    esp_err_t err = esp_ota_begin(running_partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to begin OTA operation for partition validation: %s", esp_err_to_name(err));
        return;
    }

    // Validate partition state - in typical OTA systems, we'd check if partition
    // is marked as PENDING_VERIFY or similar state
    // For now, we assume if we're here, we can proceed with marking valid

    // Mark the current partition as officially valid
