std::vector<int> Ota::ParseVersion(const std::string& version_string) {
    std::vector<int> result;

    // Handle empty string
    if (version_string.empty()) {
        return result;
    }

    // Split the version string by dots
    size_t start = 0;
    size_t end = 0;

    while (end != std::string::npos) {
        end = version_string.find('.', start);
        std::string component = version_string.substr(start, end - start);

        // Validate that component is not empty
        if (component.empty()) {
            return {}; // Return empty vector on invalid format
        }

        // Validate that component contains only digits
        for (char c : component) {
            if (!std::isdigit(c)) {
                return {}; // Return empty vector on invalid character
            }
        }

        // Convert to integer and validate non-negative
        try {
            int value = std::stoi(component);
            if (value < 0) {
                return {}; // Return empty vector on negative number
            }
            result.push_back(value);
        } catch (const std::exception&) {
            return {}; // Return empty vector on conversion error
        }

        start = end + 1;
    }

    return result;
}

bool Ota::IsNewVersionAvailable(const std::string& current_version, const std::string& candidate_version) {
    // Helper function to parse version string into segments
    auto parseVersion = [](const std::string& version) -> std::vector<int> {
        std::vector<int> segments;
        std::string segment;

        for (size_t i = 0; i <= version.length(); ++i) {
            if (i < version.length() && version[i] != '.') {
                segment += version[i];
            } else {
                if (!segment.empty()) {
                    try {
                        segments.push_back(std::stoi(segment));
                        segment.clear();
                    } catch (const std::exception&) {
                        // If conversion fails, treat as 0 or skip
                        segments.push_back(0);
                        segment.clear();
                    }
                }
            }
        }

        return segments;
    };

    // Parse both version strings
    std::vector<int> current_segments = parseVersion(current_version);
    std::vector<int> candidate_segments = parseVersion(candidate_version);

    // Compare segment by segment
    size_t max_size = std::max(current_segments.size(), candidate_segments.size());

    for (size_t i = 0; i < max_size; ++i) {
        int current_segment = (i < current_segments.size()) ? current_segments[i] : 0;
        int candidate_segment = (i < candidate_segments.size()) ? candidate_segments[i] : 0;

        if (candidate_segment > current_segment) {
            return true;  // Candidate is newer
        } else if (candidate_segment < current_segment) {
            return false; // Current is newer
        }
        // If equal, continue to next segment
    }

    // If all segments are equal, candidate is not newer
    return false;
}

