    std::string challenge = GenerateChallenge();

    // Step 4: Compute HMAC-SHA256 signature using hardware-backed key
    std::string signature = HmacSha256(serial_number + challenge);

    // Step 5: Construct and return JSON payload with serial, challenge, and signature
    std::string payload = "{";
    payload += "\"serial\":\"" + serial_number + "\",";
    payload += "\"challenge\":\"" + challenge + "\",";
    payload += "\"signature\":\"" + signature + "\"";
    payload += "}";

    return payload;
}

