esp_err_t Ota::Activate() {
    // Get device information and firmware metadata
    std::string device_id = GetDeviceId();
    std::string firmware_version = GetFirmwareVersion();

    // Construct activation payload
    json payload = {
        {"device_id", device_id},
        {"firmware_version", firmware_version},
        {"timestamp", GetTimestamp()}
    };

    // Build activation URL
    std::string activation_url = GetActivationUrl();

    // Create HTTP POST request
    HttpClient http_client;
    http_client.SetUrl(activation_url);
    http_client.SetMethod(HTTP_POST);
    http_client.SetHeader("Content-Type", "application/json");
    http_client.SetHeader("Accept", "application/json");
    http_client.SetBody(payload.dump());

    // Send request through network interface
    HttpResponse response = http_client.Send();

    // Handle response
    if (response.status_code == 200) {
        // Activation successful
        return ESP_OK;
    } else if (response.status_code == 400) {
        // Bad request - invalid payload or parameters
        ESP_LOGE(TAG, "Activation failed: Bad request");
        return ESP_ERR_INVALID_ARG;
    } else if (response.status_code == 401) {
        // Unauthorized - activation code might be invalid
        ESP_LOGE(TAG, "Activation failed: Unauthorized");
        return ESP_ERR_UNAUTHORIZED;
    } else if (response.status_code == 404) {
        // Not found - activation endpoint not found
        ESP_LOGE(TAG, "Activation failed: Endpoint not found");
        return ESP_ERR_NOT_FOUND;
    } else if (response.status_code >= 500) {
        // Server errors - retryable
        ESP_LOGE(TAG, "Activation failed: Server error %d", response.status_code);
        return ESP_ERR_TIMEOUT;
    } else {
        // Other errors
        ESP_LOGE(TAG, "Activation failed: Unknown error %d", response.status_code);
        return ESP_FAIL;
    }
}

