    esp_err_t err = nvs_set_u8(nvs_handle_, key.c_str(), value ? 1 : 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to store boolean value for key: %s, error: %s", 
                 key.c_str(), esp_err_to_name(err));
        return;
    }

    // Mark the settings as dirty to indicate that changes need to be saved
    settings_dirty_ = true;
}

void Settings::EraseKey(const std::string &key) {
    // Check if the NVS namespace is open for writing
    if (!nvs_.IsWritable()) {
        // Log a warning if the namespace is read-only and skip erasure
        ESP_LOGW(TAG, "Cannot erase key '%s': NVS namespace is read-only", key.c_str());
        return;
    }

    // Attempt to erase the specified key from NVS
    esp_err_t result = nvs_.Erase(key);

    // Handle the case where the key does not exist gracefully
    if (result == ESP_ERR_NVS_NOT_FOUND) {
        // Key doesn't exist, which is not an error condition
        ESP_LOGD(TAG, "Key '%s' not found in NVS, nothing to erase", key.c_str());
        return;
    } else if (result != ESP_OK) {
        // Handle other potential errors during erase operation
        ESP_LOGE(TAG, "Failed to erase key '%s' from NVS: %s", key.c_str(), esp_err_to_name(result));
        return;
    }

    // Successfully erased the key
    ESP_LOGD(TAG, "Successfully erased key '%s' from NVS", key.c_str());
}

void Settings::EraseAll() {
    // Check if the NVS namespace is open for writing
    nvs_handle_t nvs_handle;
    esp_err_t err = nvs_open(namespace_name_.c_str(), NVS_READWRITE, &nvs_handle);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "Failed to open NVS namespace for erasure: %s", esp_err_to_name(err));
        return;
    }

    // Check if we can actually write to this namespace
    // In ESP-IDF, if nvs_open succeeds with NVS_READWRITE, we should be able to write
    // But we'll also verify by attempting a small operation

    // Create an iterator to traverse all keys
    nvs_iterator_t iter = nvs_entry_find(NVS_DEFAULT_PART_NAME, namespace_name_.c_str(), NVS_TYPE_ANY);
    if (iter == NULL) {
        // No entries found, nothing to erase
        nvs_close(nvs_handle);
        return;
    }

    // Iterate through all entries and erase them
    bool has_entries = true;
    while (has_entries) {
        nvs_entry_info_t info;
        err = nvs_entry_get_info(iter, &info);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to get entry info during erase: %s", esp_err_to_name(err));
            break;
        }

        // Erase the current entry
        err = nvs_erase_key(nvs_handle, info.key);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to erase key '%s': %s", info.key, esp_err_to_name(err));
        } else {
            ESP_LOGI(TAG, "Erased key: %s", info.key);
        }

        // Move to next entry
        iter = nvs_entry_next(iter);
        if (iter == NULL) {
            has_entries = false;
        }
    }

    // Commit changes to NVS
    err = nvs_commit(nvs_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to commit erase operations: %s", esp_err_to_name(err));
    } else {
        ESP_LOGI(TAG, "Successfully erased all settings from namespace: %s", namespace_name_.c_str());
    }

    // Close the NVS handle
    nvs_close(nvs_handle);
}

