#include "system_info.h"
#include <esp_flash.h>

size_t SystemInfo::GetFlashSize() {
    // Get the default flash chip handle
    esp_flash_t* flash_chip = NULL;
    esp_err_t err = esp_flash_new_handle(NULL, &flash_chip);
    if (err != ESP_OK || flash_chip == NULL) {
        return 0;
    }

    // Get the flash size
    size_t flash_size = 0;
    err = esp_flash_get_size(flash_chip, &flash_size);
    if (err != ESP_OK) {
        // Clean up and return 0 on failure
        esp_flash_close(flash_chip);
        return 0;
    }

    // Clean up the flash handle
    esp_flash_close(flash_chip);

    return flash_size;
}

