static uint32_t g_task_run_time_before[configMAX_TASKS];
static uint32_t g_task_run_time_after[configMAX_TASKS];
static char g_task_names_before[configMAX_TASKS][configMAX_TASK_NAME_LEN];
static char g_task_names_after[configMAX_TASKS][configMAX_TASK_NAME_LEN];
static int g_task_count_before = 0;
static int g_task_count_after = 0;

esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait) {
    // Step 1: Initialize task statistics collection before the measurement interval
    // Collect initial task run-time statistics before delay
    g_task_count_before = 0;
    TaskHandle_t *pxTaskHandles = (TaskHandle_t *)pvPortMalloc(uxTaskGetNumberOfTasks() * sizeof(TaskHandle_t));
    if (pxTaskHandles == NULL) {
        return ESP_FAIL;
    }

    UBaseType_t uxArraySize = uxTaskGetNumberOfTasks();
    TaskStatus_t *pxTaskStatusArray = (TaskStatus_t *)pvPortMalloc(uxArraySize * sizeof(TaskStatus_t));
    if (pxTaskStatusArray == NULL) {
        vPortFree(pxTaskHandles);
        return ESP_FAIL;
    }

    // Get list of all tasks
    uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, NULL);

    // Store initial statistics
    for (UBaseType_t x = 0; x < uxArraySize; x++) {
        g_task_run_time_before[x] = pxTaskStatusArray[x].ulRunTimeCounter;
        strncpy(g_task_names_before[x], pxTaskStatusArray[x].pcTaskName, configMAX_TASK_NAME_LEN - 1);
        g_task_names_before[x][configMAX_TASK_NAME_LEN - 1] = '\0';
        g_task_count_before++;
    }

    // Step 2: Wait for the specified time interval using FreeRTOS delay mechanism
    vTaskDelay(xTicksToWait);

    // Step 3: Collect task statistics again after the delay to calculate CPU usage
    // Capture final task run-time statistics after delay
    g_task_count_after = 0;
    uxArraySize = uxTaskGetNumberOfTasks();
    uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, NULL);

    // Store final statistics
    for (UBaseType_t x = 0; x < uxArraySize; x++) {
        g_task_run_time_after[x] = pxTaskStatusArray[x].ulRunTimeCounter;
        strncpy(g_task_names_after[x], pxTaskStatusArray[x].pcTaskName, configMAX_TASK_NAME_LEN - 1);
        g_task_names_after[x][configMAX_TASK_NAME_LEN - 1] = '\0';
        g_task_count_after++;
    }

    // Step 4: Compute and display CPU usage percentages for each active task
    printf("\n=== Task CPU Usage Report ===\n");
    printf("Task Name              | CPU Usage %%\n");
    printf("-----------------------|-------------\n");

    // Calculate CPU usage for each task
    for (int i = 0; i < g_task_count_before; i++) {
        bool found = false;
        for (int j = 0; j < g_task_count_after; j++) {
            if (strcmp(g_task_names_before[i], g_task_names_after[j]) == 0) {
                found = true;
                uint32_t delta_run_time = g_task_run_time_after[j] - g_task_run_time_before[i];
                uint32_t total_run_time = 0;

                // Calculate total run time for this interval (approximate)
                for (int k = 0; k < g_task_count_after; k++) {
                    total_run_time += g_task_run_time_after[k];
                }

                float cpu_usage_percent = 0.0f;
                if (total_run_time > 0) {
                    cpu_usage_percent = ((float)delta_run_time / (float)total_run_time) * 100.0f;
                }

                printf("%-22s | %.2f%%\n", g_task_names_before[i], cpu_usage_percent);
                break;
            }
        }

        // If task was not found in final list, it might have been deleted
        if (!found) {
            printf("%-22s | Deleted during interval\n", g_task_names_before[i]);
        }
    }

    // Step 5: Identify and report any tasks created or deleted during the interval
    printf("\n--- Task Status Changes ---\n");

    // Check for newly created tasks
    for (int i = 0; i < g_task_count_after; i++) {
        bool found = false;
        for (int j = 0; j < g_task_count_before; j++) {
            if (strcmp(g_task_names_after[i], g_task_names_before[j]) == 0) {
                found = true;
                break;
            }
        }
        if (!found) {
            printf("New task created: %s\n", g_task_names_after[i]);
        }
    }

    // Step 6: Format and output the results to console with clear labeling
    printf("\n--- Measurement Complete ---\n");
    printf("Measurement interval: %d ticks\n", xTicksToWait);
    printf("Total tasks measured: %d\n", g_task_count_before);

    // Clean up memory
    vPortFree(pxTaskHandles);
    vPortFree(pxTaskStatusArray);

    return ESP_OK;
}

