void SystemInfo::PrintTaskList() {
    // Get the required buffer size for task list
    size_t bufferSize = uxTaskGetNumberOfTasks() * (configMAX_TASK_NAME_LEN + 50);

    // Allocate buffer for task list (need to account for task names and status info)
    char* buffer = new(std::nothrow) char[bufferSize];
    if (buffer == nullptr) {
        ESP_LOGE("SystemInfo", "Failed to allocate memory for task list");
        return;
    }

    // Clear the buffer
    memset(buffer, 0, bufferSize);

    // Retrieve task list using FreeRTOS vTaskList API
    vTaskList(buffer);

    // Log the task list information
    ESP_LOGI("SystemInfo", "Task List:\n%s", buffer);

    // Clean up allocated memory
    delete[] buffer;
}

