bool AudioCodec::InputData(std::vector<int16_t>& data) {
    // Check if input is enabled
    if (!input_enabled_) {
        return false;
    }

    // Check if we have valid receive handle
    if (rx_handle_ == nullptr) {
        return false;
    }

    // Get the number of samples to read
    int samples_to_read = data.size();

    // If no space in buffer, return false
    if (samples_to_read <= 0) {
        return false;
    }

    // Read audio data using the base class Read method
    int samples_read = Read(data.data(), samples_to_read);

    // Validate the read operation
    if (samples_read <= 0) {
        return false;
    }

    // Successfully read samples
    return true;
}

