void AudioCodec::Start() {
    // Configure I2S transmit handle
    i2s_chan_config_t tx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
    tx_chan_cfg.dma_desc_num = AUDIO_CODEC_DMA_DESC_NUM;
    tx_chan_cfg.dma_frame_num = AUDIO_CODEC_DMA_FRAME_NUM;

    i2s_std_config_t tx_std_cfg = {
        .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(output_sample_rate_),
        .slot_cfg = I2S_STD_MSB_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
        .gpio_cfg = {
            .mclk = GPIO_NUM_0,
            .bck = GPIO_NUM_1,
            .ws = GPIO_NUM_2,
            .dout = GPIO_NUM_3,
            .din = GPIO_NUM_NC,
        },
    };

    esp_err_t ret = i2s_new_channel(&tx_chan_cfg, &tx_std_cfg, &tx_handle_);
    if (ret != ESP_OK) {
        ESP_LOGE("AudioCodec", "Failed to create I2S TX channel: %s", esp_err_to_name(ret));
        return;
    }

    // Configure I2S receive handle
    i2s_chan_config_t rx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
    rx_chan_cfg.dma_desc_num = AUDIO_CODEC_DMA_DESC_NUM;
    rx_chan_cfg.dma_frame_num = AUDIO_CODEC_DMA_FRAME_NUM;

    i2s_std_config_t rx_std_cfg = {
        .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(input_sample_rate_),
        .slot_cfg = I2S_STD_MSB_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
        .gpio_cfg = {
            .mclk = GPIO_NUM_0,
            .bck = GPIO_NUM_1,
            .ws = GPIO_NUM_2,
            .dout = GPIO_NUM_NC,
            .din = GPIO_NUM_4,
        },
    };

    ret = i2s_new_channel(&rx_chan_cfg, &rx_std_cfg, &rx_handle_);
    if (ret != ESP_OK) {
        ESP_LOGE("AudioCodec", "Failed to create I2S RX channel: %s", esp_err_to_name(ret));
        return;
    }

    // Set initial volume levels
    SetOutputVolume(output_volume_);
    SetInputGain(input_gain_);

    // Enable audio input and output paths
    EnableInput(true);
    EnableOutput(true);

    // Verify that handles were created successfully
    if (tx_handle_ == nullptr || rx_handle_ == nullptr) {
        ESP_LOGE("AudioCodec", "Failed to initialize I2S handles");
        return;
    }

    ESP_LOGI("AudioCodec", "Audio codec started successfully");
}

