#define ES8388_ADCCONTROL120    0x7F

static const char* TAG = "ES8388_CODEC";

extern "C" void Es8388AudioCodec(void *codec_handle, i2c_port_t i2c_port, int i2c_sda_pin, int i2c_scl_pin,
                                gpio_num_t amp_enable_pin, gpio_num_t ref_input_pin, gpio_num_t reset_pin,
                                gpio_num_t mute_pin, gpio_num_t power_pin, gpio_num_t dac_mute_pin,
                                uint8_t codec_addr, bool enable_ref_input)
{
    // Initialize I2C interface for ES8388 codec control
    i2c_config_t i2c_conf = {
        .mode = I2C_MODE_MASTER,
        .sda_io_num = i2c_sda_pin,
        .scl_io_num = i2c_scl_pin,
        .sda_pullup_en = GPIO_PULLUP_ENABLE,
        .scl_pullup_en = GPIO_PULLUP_ENABLE,
        .master.clk_speed = 100000,
    };

    esp_err_t ret = i2c_param_config(i2c_port, &i2c_conf);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to configure I2C parameters");
        return;
    }

    ret = i2c_driver_install(i2c_port, I2C_MODE_MASTER, 0, 0, 0);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to install I2C driver");
        return;
    }

    // Configure GPIO pins for power amplifier control and optional reference input
    gpio_config_t io_conf = {
        .pin_bit_mask = (1ULL << amp_enable_pin) | (1ULL << ref_input_pin) | 
                        (1ULL << reset_pin) | (1ULL << mute_pin) | 
                        (1ULL << power_pin) | (1ULL << dac_mute_pin),
        .mode = GPIO_MODE_OUTPUT,
        .pull_up_en = GPIO_PULLUP_DISABLE,
        .pull_down_en = GPIO_PULLDOWN_DISABLE,
        .intr_type = GPIO_INTR_DISABLE,
    };

    gpio_config(&io_conf);

    // Set initial state of GPIOs
    gpio_set_level(amp_enable_pin, 0);   // Disable amplifier initially
    gpio_set_level(ref_input_pin, 0);    // Disable reference input initially
    gpio_set_level(reset_pin, 1);        // Reset high
    gpio_set_level(mute_pin, 1);         // Mute enabled by default
    gpio_set_level(power_pin, 0);        // Power off initially
    gpio_set_level(dac_mute_pin, 1);     // DAC mute enabled

    // Apply reset pulse to codec
    gpio_set_level(reset_pin, 0);
    vTaskDelay(10 / portTICK_PERIOD_MS);
    gpio_set_level(reset_pin, 1);
    vTaskDelay(10 / portTICK_PERIOD_MS);

    // Initialize ES8388 codec registers for audio processing and signal routing
    // First, let's check if we can communicate with the codec
