esp_err_t CreateDuplexChannels(gpio_num_t mclk_pin, gpio_num_t ws_pin, gpio_num_t bclk_pin, gpio_num_t din_pin, gpio_num_t dout_pin) {
    // Initialize I2S peripheral in master mode for full-duplex audio communication
    i2s_config_t i2s_config = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX),
        .sample_rate = 44100,  // Standard sample rate for audio
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = (i2s_comm_format_t)(I2S_COMM_FORMAT_I2S | I2S_COMM_FORMAT_I2S_MSB),
        .dma_buf_count = 8,
        .dma_buf_len = 64,
        .use_apll = false,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0
    };

    // Set up GPIO pins for I2S signal lines
    i2s_pin_config_t pin_config = {
        .bck_io_num = bclk_pin,
        .ws_io_num = ws_pin,
        .data_out_num = dout_pin,
        .data_in_num = din_pin
    };

    // Configure MCLK pin as output
    gpio_config_t mclk_config = {
        .pin_bit_mask = (1ULL << mclk_pin),
        .mode = GPIO_MODE_OUTPUT,
        .pull_up_en = GPIO_PULLUP_DISABLE,
        .pull_down_en = GPIO_PULLDOWN_DISABLE,
        .intr_type = GPIO_INTR_DISABLE
    };

    esp_err_t ret = gpio_config(&mclk_config);
    if (ret != ESP_OK) {
        return ret;
    }

    // Initialize I2S driver with the configured parameters
    ret = i2s_driver_install(I2S_NUM_0, &i2s_config, 0, NULL);
    if (ret != ESP_OK) {
        return ret;
    }

    // Set up I2S pin configuration
    ret = i2s_set_pin(I2S_NUM_0, &pin_config);
    if (ret != ESP_OK) {
        i2s_driver_uninstall(I2S_NUM_0);
        return ret;
    }

    // Configure I2S clock and sample rate according to ES8388 requirements
    // For ES8388, we typically use 44.1kHz or 48kHz sample rates
    ret = i2s_set_clk(I2S_NUM_0, 44100, I2S_BITS_PER_SAMPLE_16BIT, I2S_CHANNEL_STEREO);
    if (ret != ESP_OK) {
        i2s_driver_uninstall(I2S_NUM_0);
        return ret;
    }

    // Enable simultaneous transmit and receive channels for duplex operation
    // The I2S driver is already configured for full-duplex in the mode setting above

    // Validate GPIO configurations and I2S setup before finalizing
    // Check if all required GPIOs are properly configured
    if (mclk_pin == GPIO_NUM_NC || ws_pin == GPIO_NUM_NC || 
        bclk_pin == GPIO_NUM_NC || din_pin == GPIO_NUM_NC || 
        dout_pin == GPIO_NUM_NC) {
        i2s_driver_uninstall(I2S_NUM_0);
        return ESP_ERR_INVALID_ARG;
    }

    // Set MCLK to high to enable codec
    gpio_set_level(mclk_pin, 1);

    return ESP_OK;
}

