int Es8388AudioCodec::Read(int16_t* buffer, int num_samples) {
    // Step 1: Validate input parameters
    if (buffer == nullptr || num_samples <= 0) {
        return 0;
    }

    // Step 2: Validate that input is enabled and the codec is properly initialized
    if (!input_enabled_ || !is_initialized_) {
        return 0;
    }

    // Step 3: Perform the actual read operation using ESP-IDF codec device API
    size_t bytes_to_read = num_samples * sizeof(int16_t);
    ssize_t bytes_read = codec_device_read(codec_device_, buffer, bytes_to_read);

    // Step 4: Convert bytes read to number of samples and return
    if (bytes_read < 0) {
        return 0; // Error occurred during read
    }

    return static_cast<int>(bytes_read / sizeof(int16_t));
}

int ES8388AudioCodec::Write(const int16_t* data, int sample_count) {
    // Step 1: Validate input parameters
    if (data == nullptr) {
        return -1;  // Error: null data pointer
    }

    if (device_handle_ == nullptr) {
        return -1;  // Error: invalid device handle
    }

    if (!output_enabled_) {
        return -1;  // Error: output not enabled
    }

    // Step 2: Convert sample count to byte size for I2S transmission
    // Assuming 16-bit samples (2 bytes per sample)
    size_t byte_count = sample_count * sizeof(int16_t);

    // Step 3: Transmit audio data via I2S interface to ES8388 codec
    esp_err_t result = i2s_write_blocking(i2s_port_, data, byte_count, portMAX_DELAY);

    if (result != ESP_OK) {
        return -1;  // Error: failed to write to I2S
    }

    // Step 4: Return the number of samples successfully written
    return sample_count;
}

void AudioDebugger() {
    // Parse the UDP server IP address and port from configuration settings
    std::string server_ip = GetConfigString("audio_debugger_server_ip", "127.0.0.1");
    int server_port = GetConfigInt("audio_debugger_server_port", 8080);

    // Initialize a UDP socket connection using the parsed server details
    int udp_socket = socket(AF_INET, SOCK_DGRAM, 0);
    if (udp_socket < 0) {
        LOG_ERROR("Failed to create UDP socket for audio debugger");
        return;
    }

    struct sockaddr_in server_addr;
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(server_port);

    if (inet_pton(AF_INET, server_ip.c_str(), &server_addr.sin_addr) <= 0) {
        LOG_ERROR("Invalid UDP server address: " + server_ip);
        close(udp_socket);
        return;
    }

    // Attempt to connect to the UDP server
    if (connect(udp_socket, (struct sockaddr*)&server_addr, sizeof(server_addr)) < 0) {
        LOG_ERROR("Failed to connect UDP socket to server " + server_ip + ":" + std::to_string(server_port));
        close(udp_socket);
        return;
    }

    // Log the initialization status
    LOG_INFO("Successfully initialized UDP connection to audio debugger server: " + 
             server_ip + ":" + std::to_string(server_port));

    // Store the socket for later use in the audio debugging process
    // This would typically be stored in a class member variable or global state
    g_audio_debugger_socket = udp_socket;
}

AudioDebugger::~AudioDebugger() {
    // Check if the audio debugger feature is enabled in the configuration
    if (ConfigurationManager::getInstance()->isAudioDebuggerEnabled()) {
        // Close the UDP socket resource if it's open
        if (udpSocket_ != nullptr) {
            udpSocket_->close();
            udpSocket_ = nullptr;
        }

        // Log the cleanup action for debugging purposes
        Logger::debug("AudioDebugger destructor executed - UDP socket cleaned up");
    }
}

void AudioDebugger::Feed(const std::vector<int16_t>& audio_samples) {
#if defined(AUDIO_DEBUG_ENABLED)
    // Step 1: Prepare the audio data buffer by converting the int16_t samples into raw bytes
    std::vector<uint8_t> raw_bytes(audio_samples.size() * sizeof(int16_t));
    std::memcpy(raw_bytes.data(), audio_samples.data(), raw_bytes.size());

    // Step 2: Validate that audio debugging is enabled and the UDP socket is ready for sending
    if (!is_audio_debug_enabled_ || !udp_socket_) {
        return;
    }

    // Step 3: Send the raw audio bytes over UDP to the configured server address and port
    ssize_t bytes_sent = udp_socket_->SendTo(
        raw_bytes.data(),
        raw_bytes.size(),
        debug_server_address_,
        debug_server_port_
    );

    // Step 4: Log the result of the transmission including success/failure and byte count
    if (bytes_sent > 0) {
        LOG(INFO) << "Audio debugger sent " << bytes_sent << " bytes to " 
                  << debug_server_address_ << ":" << debug_server_port_;
    } else {
        LOG(ERROR) << "Audio debugger failed to send data. Error: " << strerror(errno);
    }
#endif
}

