AfeWakeWord::~AfeWakeWord() {
    // Clean up the AFE (Acoustic Front End) instance
    if (afe_data_) {
        // Deallocate AFE resources
        if (afe_iface_ && afe_iface_->destroy) {
            afe_iface_->destroy(afe_data_);
        }
        afe_data_ = nullptr;
        afe_iface_ = nullptr;
    }

    // Release the wake word encoding task stack and associated buffer memory
    if (wake_word_encode_task_ != nullptr) {
        // Delete the task
        vTaskDelete(wake_word_encode_task_);
        wake_word_encode_task_ = nullptr;
    }

    if (wake_word_encode_task_buffer_ != nullptr) {
        // Free the static task buffer
        // Note: In FreeRTOS, StaticTask_t is typically allocated statically,
        // so we don't free it directly, but we clear the pointer
        wake_word_encode_task_buffer_ = nullptr;
    }

    if (wake_word_encode_task_stack_ != nullptr) {
        // Free the stack memory
        vPortFree(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
    }

    // Deinitialize speech recognition models and free their allocated memory
    if (models_ != nullptr) {
        // Free the model list
        if (models_->model_list != nullptr) {
            free(models_->model_list);
            models_->model_list = nullptr;
        }
        free(models_);
        models_ = nullptr;
    }

    // Delete the event group used for synchronization between wake word detection tasks
    if (event_group_ != nullptr) {
        vEventGroupDelete(event_group_);
        event_group_ = nullptr;
    }

    // Clear other member variables
    wakenet_model_ = nullptr;
    wake_words_.clear();
    last_detected_wake_word_.clear();
}

bool AfeWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* model_list) {
    // Step 1: Configure the audio codec with initial settings for wake word detection
    if (!codec) {
        return false;
    }

    // Configure I2S settings for wake word detection
    codec->SetSampleRate(16000);  // Common sample rate for voice applications
    codec->SetChannels(1);        // Mono audio for wake word detection
    codec->SetBitDepth(16);       // 16-bit audio samples

    // Enable necessary audio paths for wake word detection
    codec->EnableInputPath();
    codec->EnableOutputPath();

    // Set gain levels appropriate for wake word detection
    codec->SetInputGain(30);      // Adjust as needed for your hardware
    codec->SetOutputGain(50);     // Adjust as needed for your hardware

    // Step 2: Load and validate wake word models from the provided model list
    if (!model_list) {
        return false;
    }

    // Validate and load each model in the model list
    for (int i = 0; i < model_list->num_models; i++) {
        if (!model_list->models[i]) {
            return false;
        }

        // Perform basic validation of the model
        if (model_list->models[i]->version != MODEL_VERSION) {
            return false;
        }

        // Load model into memory (implementation depends on specific model format)
        if (!LoadWakeWordModel(model_list->models[i])) {
            return false;
        }
    }

    // Step 3: Initialize the AFE processing pipeline with echo cancellation and memory allocation
    // Initialize AFE framework components
    if (!afe_framework_.Initialize()) {
        return false;
    }

    // Setup AEC (Acoustic Echo Cancellation) parameters
    afe_framework_.SetAecEnabled(true);
    afe_framework_.SetAecDelay(100);  // Set appropriate delay for your application

    // Configure VAD (Voice Activity Detection) settings
    afe_framework_.SetVadThreshold(0.5f);  // Adjust sensitivity as needed
    afe_framework_.SetVadWindowDuration(20);  // 20ms window

    // Allocate memory for audio buffers
    const size_t buffer_size = 1024 * sizeof(int16_t);  // 1KB buffer for audio data
    audio_buffer_ = new int16_t[buffer_size / sizeof(int16_t)];
    if (!audio_buffer_) {
        return false;
    }

    // Allocate memory for intermediate processing buffers
    process_buffer_ = new float[buffer_size / sizeof(int16_t)];
    if (!process_buffer_) {
        delete[] audio_buffer_;
        return false;
    }

    // Initialize memory pool for dynamic allocations
    memory_pool_.Initialize(buffer_size * 2);  // Reserve space for two buffers

    // Step 4: Start the dedicated task for real-time audio detection
    // Create and start the audio detection task
    TaskHandle_t task_handle = nullptr;
    BaseType_t result = xTaskCreate(
        AudioDetectionTask,           // Task function
        "WakeWordDetection",          // Task name
        4096,                         // Stack size in words
        this,                         // Task parameter
        configMAX_PRIORITIES - 1,     // Task priority
        &task_handle                  // Task handle
    );

    if (result != pdPASS || !task_handle) {
        // Cleanup allocated resources on failure
        delete[] audio_buffer_;
        delete[] process_buffer_;
        return false;
    }

    // Store task handle for potential later operations
    detection_task_handle_ = task_handle;

    // Mark initialization as complete
    initialized_ = true;

    return true;
}

