void AfeWakeWord::Stop() {
    // Clear the detection running event flag to stop wake word detection processing
    xEventGroupClearBits(event_group_, DETECTION_RUNNING_EVENT);

    // Reset the audio front-end buffer if it has been initialized
    if (afe_data_ != nullptr) {
        // Clear the wake word PCM buffer to remove any buffered data
        std::lock_guard<std::mutex> lock(wake_word_mutex_);
        wake_word_pcm_.clear();
        wake_word_opus_.clear();
    }
}

void AfeWakeWord::Feed(const std::vector<int16_t>& samples) {
  // Step 1: Validate the internal AFE data buffer to ensure it is properly initialized
  // and ready for audio processing
  if (!IsBufferValid()) {
    // Handle invalid buffer case - could log error or return early
    return;
  }

  // Step 2: Copy the incoming PCM audio samples into the AFE processing pipeline
  // for further analysis
  if (!FeedAudioData(samples)) {
    // Handle failure to feed audio data
    return;
  }

  // Step 3: Trigger the underlying AFE interface to perform voice activity 
  // detection and wake word recognition on the fed data
  Process();
}

