size_t AfeWakeWord::GetFeedSize() {
    // Check if AFE data is initialized
    if (afe_data_ == nullptr) {
        return 0;
    }

    // Retrieve the required audio frame size from AFE interface
    // Based on ESP-IDF AFE API patterns, this would typically be the number
    // of samples needed per frame for wake word detection
    if (afe_iface_ && afe_iface_->get_feed_size) {
        return afe_iface_->get_feed_size(afe_data_);
    }

    // Fallback: return a reasonable default or 0 if unable to determine
    return 0;
}

