void AfeWakeWord::StoreWakeWordData(const int16_t* data, size_t length) {
  // Check if the input data is valid
  if (data == nullptr || length == 0) {
    return;
  }

  // Calculate how many samples we can store in 2 seconds
  // Assuming 16000 samples per second (16kHz sampling rate)
  const size_t kMaxSamples = 2 * 16000;

  // If the incoming data is larger than our buffer, we only take what fits
  size_t samples_to_store = std::min(length, kMaxSamples);

  // Handle case where we're storing less than the full buffer
  if (samples_to_store < kMaxSamples) {
    // If we have space, just copy the data
    if (buffer_write_index_ + samples_to_store <= kMaxSamples) {
      memcpy(&audio_buffer_[buffer_write_index_], data, 
             samples_to_store * sizeof(int16_t));
      buffer_write_index_ += samples_to_store;
    } else {
      // Handle wraparound - first part
      size_t first_part_size = kMaxSamples - buffer_write_index_;
      memcpy(&audio_buffer_[buffer_write_index_], data, 
             first_part_size * sizeof(int16_t));

      // Second part if needed
      if (samples_to_store > first_part_size) {
        memcpy(audio_buffer_, &data[first_part_size], 
               (samples_to_store - first_part_size) * sizeof(int16_t));
        buffer_write_index_ = samples_to_store - first_part_size;
      } else {
        buffer_write_index_ += samples_to_store;
      }
    }
  } else {
    // We're overwriting the entire buffer, so just copy all data
    memcpy(audio_buffer_, data, kMaxSamples * sizeof(int16_t));
    buffer_write_index_ = 0;  // Reset to beginning
  }
}

