void AfeWakeWord::EncodeWakeWordData() {
    // Initialize Opus encoder with low complexity settings for real-time PCM to Opus encoding
    OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
    if (!encoder) {
        return;
    }

    // Set encoder to low complexity mode for real-time encoding
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000));

    // Allocate memory for task stack and buffer using SPIRAM and internal memory
    const size_t stack_size = 4096;
    const size_t buffer_size = 1024;

    // Allocate static task structure
    wake_word_encode_task_buffer_ = new StaticTask_t;
    if (!wake_word_encode_task_buffer_) {
        opus_encoder_destroy(encoder);
        return;
    }

    // Allocate stack memory - try SPIRAM first, fallback to internal RAM
    wake_word_encode_task_stack_ = (StackType_t*)heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
    if (!wake_word_encode_task_stack_) {
        wake_word_encode_task_stack_ = (StackType_t*)malloc(stack_size);
    }

    if (!wake_word_encode_task_stack_) {
        delete wake_word_encode_task_buffer_;
        opus_encoder_destroy(encoder);
        return;
    }

    // Create the real-time task for encoding wake word data
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void* arg) {
            AfeWakeWord* self = static_cast<AfeWakeWord*>(arg);
            self->EncodeWakeWordData();
        },
        "wake_word_encode",
        stack_size,
        this,
        tskIDLE_PRIORITY + 1,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (wake_word_encode_task_ == NULL) {
        heap_caps_free(wake_word_encode_task_stack_);
        delete wake_word_encode_task_buffer_;
        opus_encoder_destroy(encoder);
        return;
    }

    // Process incoming PCM audio packets in a loop, encoding each packet into Opus format
    while (true) {
        // Wait for new PCM data to be available
        std::unique_lock<std::mutex> lock(wake_word_mutex_);
        wake_word_cv_.wait(lock, [this] { 
            return !wake_word_pcm_.empty(); 
        });

        // Process all available PCM packets
        while (!wake_word_pcm_.empty()) {
            auto pcm_packet = wake_word_pcm_.front();
            wake_word_pcm_.pop_front();

            lock.unlock();

            // Encode PCM packet to Opus format
            std::vector<uint8_t> opus_packet(buffer_size);
            int opus_len = opus_encode(encoder, pcm_packet.data(), pcm_packet.size() / sizeof(int16_t), 
                                     reinterpret_cast<char*>(opus_packet.data()), buffer_size);

            if (opus_len > 0) {
                // Resize to actual encoded length
                opus_packet.resize(opus_len);

                // Store encoded Opus packet in thread-safe buffer for subsequent processing or transmission
                std::lock_guard<std::mutex> buffer_lock(wake_word_mutex_);
                wake_word_opus_.push_back(std::move(opus_packet));
            }

            lock.lock();
        }
    }

    // Clean up resources when done
    opus_encoder_destroy(encoder);
}

