bool CustomWakeWord::ParseWakenetModelConfig() {
    // Read and load the index.json configuration file from storage
    FILE* fp = fopen("/spiffs/index.json", "r");
    if (fp == NULL) {
        ESP_LOGE(TAG, "Failed to open index.json file");
        return false;
    }

    // Get file size
    fseek(fp, 0, SEEK_END);
    long file_size = ftell(fp);
    fseek(fp, 0, SEEK_SET);

    // Allocate memory for file content
    char* json_buffer = new char[file_size + 1];
    if (json_buffer == NULL) {
        fclose(fp);
        ESP_LOGE(TAG, "Failed to allocate memory for JSON buffer");
        return false;
    }

    // Read file content
    size_t bytes_read = fread(json_buffer, 1, file_size, fp);
    json_buffer[bytes_read] = '\0';
    fclose(fp);

    // Parse JSON
    cJSON* root = cJSON_Parse(json_buffer);
    delete[] json_buffer;

    if (root == NULL) {
        ESP_LOGE(TAG, "Failed to parse JSON: %s", cJSON_GetErrorPtr());
        return false;
    }

    // Extract language
    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (language_item && cJSON_IsString(language_item)) {
        language_ = std::string(language_item->valuestring);
    } else {
        ESP_LOGW(TAG, "Language not found or invalid in config, using default");
        language_ = "en"; // Default language
    }

    // Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valuedouble;
    } else {
        ESP_LOGW(TAG, "Duration not found or invalid in config, using default");
        duration_ = 2.0; // Default duration in seconds
    }

    // Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item && cJSON_IsNumber(threshold_item)) {
        threshold_ = threshold_item->valuedouble;
    } else {
        ESP_LOGW(TAG, "Threshold not found or invalid in config, using default");
        threshold_ = 0.8; // Default threshold
    }

    // Extract commands
    cJSON* commands_item = cJSON_GetObjectItem(root, "commands");
    if (commands_item && cJSON_IsArray(commands_item)) {
        int num_commands = cJSON_GetArraySize(commands_item);
        commands_.clear();

        for (int i = 0; i < num_commands; i++) {
            cJSON* command_obj = cJSON_GetArrayItem(commands_item, i);
            if (command_obj && cJSON_IsObject(command_obj)) {
                WakeWordCommand command;

                // Extract command name
                cJSON* name_item = cJSON_GetObjectItem(command_obj, "name");
                if (name_item && cJSON_IsString(name_item)) {
                    command.name = std::string(name_item->valuestring);
                } else {
                    ESP_LOGW(TAG, "Command name missing in config");
                    continue;
                }

                // Extract command phrase
                cJSON* phrase_item = cJSON_GetObjectItem(command_obj, "phrase");
                if (phrase_item && cJSON_IsString(phrase_item)) {
                    command.phrase = std::string(phrase_item->valuestring);
                } else {
                    ESP_LOGW(TAG, "Command phrase missing in config for command: %s", command.name.c_str());
                    continue;
                }

                // Extract command action
                cJSON* action_item = cJSON_GetObjectItem(command_obj, "action");
                if (action_item && cJSON_IsString(action_item)) {
                    command.action = std::string(action_item->valuestring);
                } else {
                    ESP_LOGW(TAG, "Command action missing in config for command: %s", command.name.c_str());
                    continue;
                }

                // Extract confidence (optional)
                cJSON* confidence_item = cJSON_GetObjectItem(command_obj, "confidence");
                if (confidence_item && cJSON_IsNumber(confidence_item)) {
                    command.confidence = confidence_item->valuedouble;
                } else {
                    command.confidence = 0.9; // Default confidence
                }

                commands_.push_back(command);

                // Log each parsed command for debugging
                ESP_LOGI(TAG, "Parsed command: %s -> %s (action: %s, confidence: %.2f)", 
                        command.name.c_str(), 
                        command.phrase.c_str(), 
                        command.action.c_str(), 
                        command.confidence);
            }
        }
    } else {
        ESP_LOGW(TAG, "Commands array not found or invalid in config");
    }

    // Clean up
    cJSON_Delete(root);

    return true;
}

bool CustomWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *model_list) {
    // Step 1: Configure the audio codec with initial settings for wake word detection
    if (!codec) {
        return false;
    }

    // Set audio codec to appropriate settings for wake word detection
    // Typical settings might include sample rate, bit depth, and input configuration
    codec->SetSampleRate(16000);  // Common sample rate for voice applications
    codec->SetBitDepth(16);       // 16-bit audio
    codec->SetChannels(1);        // Mono audio
    codec->EnableInput();         // Enable input for recording

    // Step 2: Load and validate the voice recognition models from the provided model list
    if (!model_list) {
        return false;
    }

    // Validate that we have the required models for wake word detection
    // This would typically check for presence of necessary model files
    if (model_list->num_models == 0) {
        return false;
    }

    // Step 3: Register custom voice commands and set up language-specific thresholds
    // Initialize default thresholds for wake word detection
    this->threshold_ = 0.8f;  // Default confidence threshold
    this->language_ = "en";   // Default language

    // Register any custom voice commands that might be part of the wake word system
    // In a real implementation, this would register actual command handlers

    // Step 4: Initialize the multinet model for speech command recognition
    // This would typically involve loading the neural network model into memory
    // and preparing it for inference
    if (!this->multinet_model_.Initialize(model_list)) {
        return false;
    }

    // Step 5: Verify all components are properly initialized and return success status
    // Check that all critical components are ready
    if (!codec->IsInitialized() || !this->multinet_model_.IsReady()) {
        return false;
    }

    // Mark the wake word system as initialized
    this->is_initialized_ = true;

    return true;
}

bool CustomWakeWord::Feed(const std::vector<int16_t>& audio_data) {
    // Validate input audio data
    if (audio_data.empty()) {
        return false;
    }

    // Handle mono/stereo conversion - extract left channel if stereo
    std::vector<int16_t> processed_audio;
    if (audio_channels_ == 2) {
        // For stereo input, extract left channel (assuming interleaved format)
        processed_audio.reserve(audio_data.size() / 2);
        for (size_t i = 0; i < audio_data.size(); i += 2) {
            processed_audio.push_back(audio_data[i]);
        }
    } else {
        processed_audio = audio_data;
    }

    // Store processed audio frames in internal buffer
    audio_buffer_.insert(audio_buffer_.end(), processed_audio.begin(), processed_audio.end());

    // Check if we have enough frames for processing
    const size_t required_frames = multinet_model_->GetRequiredFrames();
    if (audio_buffer_.size() < required_frames) {
        return true; // Not enough data yet
    }

    // Run multinet model inference on buffered audio data
    std::vector<float> normalized_audio;
    normalized_audio.reserve(audio_buffer_.size());
    for (const auto& sample : audio_buffer_) {
        normalized_audio.push_back(static_cast<float>(sample) / 32768.0f);
    }

    // Perform inference
    std::vector<float> results;
    bool inference_success = multinet_model_->RunInference(normalized_audio, &results);

    if (!inference_success) {
        return false;
    }

    // Check for wake word detection
    int detected_keyword = multinet_model_->GetDetectedKeyword(results);
    if (detected_keyword >= 0 && detected_keyword < wake_words_.size()) {
        // Trigger callback upon successful wake word detection
        if (wake_word_callback_) {
            wake_word_callback_(wake_words_[detected_keyword]);
        }

        // Pause processing until reactivated after detection
        is_processing_paused_ = true;
        return true;
    }

    // Remove processed frames from buffer to maintain sliding window
    const size_t frames_to_remove = processed_audio.size();
    if (audio_buffer_.size() > frames_to_remove) {
        audio_buffer_.erase(audio_buffer_.begin(), audio_buffer_.begin() + frames_to_remove);
    } else {
        audio_buffer_.clear();
    }

    return true;
}

