// Assuming a standard sample rate of 16kHz (common for voice applications)
// 2 seconds of audio at 16kHz = 32000 samples
static const int SAMPLE_RATE = 16000;
static const int BUFFER_SIZE_SAMPLES = SAMPLE_RATE * 2; // 2 seconds

void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t>& audio_data) {
    std::lock_guard<std::mutex> lock(buffer_mutex_);

    // If we're adding more data than our buffer can hold, only take the latest portion
    if (audio_data.size() >= BUFFER_SIZE_SAMPLES) {
        // Overwrite entire buffer with the newest data
        audio_buffer_.clear();
        audio_buffer_.reserve(BUFFER_SIZE_SAMPLES);
        audio_buffer_.assign(audio_data.end() - BUFFER_SIZE_SAMPLES, audio_data.end());
        buffer_write_index_ = 0;
        return;
    }

    // Calculate how much space we have left in the buffer
    int available_space = BUFFER_SIZE_SAMPLES - buffer_write_index_;

    if (available_space >= static_cast<int>(audio_data.size())) {
        // Enough space at end of buffer
        audio_buffer_.insert(audio_buffer_.begin() + buffer_write_index_, 
                           audio_data.begin(), audio_data.end());
        buffer_write_index_ += audio_data.size();
    } else {
        // Need to wrap around - fill remaining space at end, then start from beginning
        int first_part_size = available_space;
        int second_part_size = audio_data.size() - first_part_size;

        // Fill remaining space at end
        audio_buffer_.insert(audio_buffer_.begin() + buffer_write_index_, 
                           audio_data.begin(), audio_data.begin() + first_part_size);

        // Fill from beginning
        audio_buffer_.insert(audio_buffer_.end(), 
                           audio_data.begin() + first_part_size, audio_data.end());

        buffer_write_index_ = second_part_size;
    }

    // Maintain exactly 2 seconds of data by trimming excess
    if (audio_buffer_.size() > BUFFER_SIZE_SAMPLES) {
        int excess = audio_buffer_.size() - BUFFER_SIZE_SAMPLES;
        audio_buffer_.erase(audio_buffer_.begin(), audio_buffer_.begin() + excess);
        buffer_write_index_ = BUFFER_SIZE_SAMPLES;
    }
}

