void AfeWakeWord::EncodeWakeWordData() {
    // Initialize memory for the encoding task including stack and buffer allocation
    wake_word_encode_task_buffer_ = new StaticTask_t;
    wake_word_encode_task_stack_ = new StackType_t[configMINIMAL_STACK_SIZE];

    // Set up and configure the Opus encoder with low complexity settings
    OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
    if (encoder == NULL) {
        // Handle error - could not create encoder
        return;
    }

    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(12000));

    // Process each PCM audio segment by encoding it into Opus format
    std::vector<int16_t> pcm_segment;
    std::vector<uint8_t> opus_segment;

    {
        std::lock_guard<std::mutex> lock(wake_word_mutex_);
        while (!wake_word_pcm_.empty()) {
            pcm_segment = wake_word_pcm_.front();
            wake_word_pcm_.pop_front();

            // Allocate buffer for encoded data
            opus_segment.resize(pcm_segment.size() * 2); // Conservative estimate

            // Encode the PCM segment
            int encoded_size = opus_encode(encoder, 
                                          pcm_segment.data(), 
                                          pcm_segment.size(), 
                                          opus_segment.data(), 
                                          opus_segment.size());

            if (encoded_size > 0) {
                // Resize to actual encoded size
                opus_segment.resize(encoded_size);

                // Add to output queue
                wake_word_opus_.push_back(opus_segment);
            }
        }
    }

    // Signal completion of encoding and append termination marker to stream
    opus_segment.clear();
    opus_segment.push_back(0xFF); // Termination marker
    opus_segment.push_back(0xFF); // Termination marker

    {
        std::lock_guard<std::mutex> lock(wake_word_mutex_);
        wake_word_opus_.push_back(opus_segment);
    }

    // Clean up
    opus_encoder_destroy(encoder);

    // Free allocated memory
    delete[] wake_word_encode_task_stack_;
    delete wake_word_encode_task_buffer_;
}

