static const char* TAG = "XL9555";

void XL9555(i2c_master_bus_handle_t bus_handle, uint8_t address)
{
    // Define XL9555 register addresses
    const uint8_t REG_INPUT_PORT0 = 0x00;
    const uint8_t REG_INPUT_PORT1 = 0x01;
    const uint8_t REG_OUTPUT_PORT0 = 0x02;
    const uint8_t REG_OUTPUT_PORT1 = 0x03;
    const uint8_t REG_INVERSION_PORT0 = 0x04;
    const uint8_t REG_INVERSION_PORT1 = 0x05;
    const uint8_t REG_CONFIG_PORT0 = 0x06;
    const uint8_t REG_CONFIG_PORT1 = 0x07;

    // Default configuration: all pins as outputs (0x00)
    const uint8_t DEFAULT_CONFIG_PORT0 = 0x00;
    const uint8_t DEFAULT_CONFIG_PORT1 = 0x00;

    // Default output state: all pins low (0x00)
    const uint8_t DEFAULT_OUTPUT_PORT0 = 0x00;
    const uint8_t DEFAULT_OUTPUT_PORT1 = 0x00;

    // Initialize I2C communication with the XL9555 device
    i2c_cmd_handle_t cmd = i2c_cmd_link_create();

    // Configure the device by writing to configuration registers
    // Set all pins as outputs (configuration register 0x06 and 0x07)
    i2c_master_start(cmd);
    i2c_master_write_byte(cmd, (address << 1) | I2C_MASTER_WRITE, true);

    // Write to CONFIG_PORT0 register (0x06)
    i2c_master_write_byte(cmd, REG_CONFIG_PORT0, true);
    i2c_master_write_byte(cmd, DEFAULT_CONFIG_PORT0, true);

    // Write to CONFIG_PORT1 register (0x07)
    i2c_master_write_byte(cmd, REG_CONFIG_PORT1, true);
    i2c_master_write_byte(cmd, DEFAULT_CONFIG_PORT1, true);

    // Write to OUTPUT_PORT0 register (0x02) - set initial output state
    i2c_master_write_byte(cmd, REG_OUTPUT_PORT0, true);
    i2c_master_write_byte(cmd, DEFAULT_OUTPUT_PORT0, true);

    // Write to OUTPUT_PORT1 register (0x03) - set initial output state
    i2c_master_write_byte(cmd, REG_OUTPUT_PORT1, true);
    i2c_master_write_byte(cmd, DEFAULT_OUTPUT_PORT1, true);

    i2c_master_stop(cmd);

    // Execute the command
    esp_err_t result = i2c_master_cmd_begin(bus_handle, cmd, 1000 / portTICK_PERIOD_MS);
    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to configure XL9555 device at address 0x%02X", address);
        i2c_cmd_link_delete(cmd);
        return;
    }

    i2c_cmd_link_delete(cmd);

    // Verify successful initialization by reading back the configuration registers
    uint8_t read_config_port0 = 0;
    uint8_t read_config_port1 = 0;

    cmd = i2c_cmd_link_create();

    // Read back CONFIG_PORT0
    i2c_master_start(cmd);
    i2c_master_write_byte(cmd, (address << 1) | I2C_MASTER_WRITE, true);
    i2c_master_write_byte(cmd, REG_CONFIG_PORT0, true);
    i2c_master_stop(cmd);

    result = i2c_master_cmd_begin(bus_handle, cmd, 1000 / portTICK_PERIOD_MS);
    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to send read command for CONFIG_PORT0");
        i2c_cmd_link_delete(cmd);
        return;
    }

    i2c_cmd_link_delete(cmd);

    cmd = i2c_cmd_link_create();
    i2c_master_start(cmd);
    i2c_master_write_byte(cmd, (address << 1) | I2C_MASTER_READ, true);
    i2c_master_read_byte(cmd, &read_config_port0, I2C_MASTER_ACK);
    i2c_master_read_byte(cmd, &read_config_port1, I2C_MASTER_NACK);
    i2c_master_stop(cmd);

    result = i2c_master_cmd_begin(bus_handle, cmd, 1000 / portTICK_PERIOD_MS);
    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read configuration registers from XL9555 device");
        i2c_cmd_link_delete(cmd);
        return;
    }

    i2c_cmd_link_delete(cmd);

    // Check if the read values match our expected configuration
    if (read_config_port0 == DEFAULT_CONFIG_PORT0 && 
        read_config_port1 == DEFAULT_CONFIG_PORT1) {
        ESP_LOGI(TAG, "XL9555 device at address 0x%02X initialized successfully", address);
    } else {
        ESP_LOGW(TAG, "XL9555 device at address 0x%02X configuration mismatch", address);
    }
}

void SetOutputState(uint8_t pin, uint8_t level) {
    // Define GPIO output enable register base address
    // For ESP32-S3, GPIO output enable is typically controlled via GPIO_OUT_W1TS_REG and GPIO_OUT_W1TC_REG
    // or GPIO_OUT_REG for direct access

    // GPIO output register offset (this may vary based on exact register map)
    const uint32_t GPIO_OUT_REG_ADDR = 0x60004000 + 0x0000; // Base address + offset for GPIO_OUT

    // GPIO enable register offset 
    const uint32_t GPIO_ENABLE_REG_ADDR = 0x60004000 + 0x0004; // Base address + offset for GPIO_ENABLE

    // Get the current register value
    volatile uint32_t* gpio_out_reg = (volatile uint32_t*)GPIO_OUT_REG_ADDR;
    volatile uint32_t* gpio_enable_reg = (volatile uint32_t*)GPIO_ENABLE_REG_ADDR;

    // Read current register value
    uint32_t current_value = *gpio_out_reg;

    // Create mask for the specific pin
    uint32_t pin_mask = 1 << pin;

    // Modify the specific bit based on desired level
    if (level) {
        // Set the pin high (set bit)
        current_value |= pin_mask;
    } else {
        // Set the pin low (clear bit)
        current_value &= ~pin_mask;
    }

    // Write the updated register value back to hardware
    *gpio_out_reg = current_value;

    // Ensure the pin is configured as output (set GPIO enable bit)
    uint32_t enable_value = *gpio_enable_reg;
    enable_value |= pin_mask;
    *gpio_enable_reg = enable_value;
}

void InitializeI2c() {
    // Configure I2C master interface
    i2c_config_t i2c_conf = {
        .mode = I2C_MODE_MASTER,
        .sda_io_num = GPIO_NUM_18,  // Assuming SDA pin is GPIO18
        .scl_io_num = GPIO_NUM_19,  // Assuming SCL pin is GPIO19
        .sda_pullup_en = GPIO_PULLUP_ENABLE,
        .scl_pullup_en = GPIO_PULLUP_ENABLE,
        .master.clk_speed = 100000,  // 100kHz clock speed
    };

    // Install I2C driver
    esp_err_t err = i2c_param_config(I2C_NUM_0, &i2c_conf);
    if (err != ESP_OK) {
        // Handle error appropriately
        return;
    }

    err = i2c_driver_install(I2C_NUM_0, I2C_MODE_MASTER, 0, 0, 0);
    if (err != ESP_OK) {
        // Handle error appropriately
        return;
    }

    // Initialize XL9555 I/O expander at address 0x20
    // Set all ports to output mode (default register values)
    uint8_t config_reg[2] = {0x00, 0x00};  // All pins as outputs

    // Write configuration registers to XL9555
    i2c_cmd_handle_t cmd = i2c_cmd_link_create();
    i2c_master_start(cmd);
    i2c_master_write_byte(cmd, (0x20 << 1) | I2C_MASTER_WRITE, true);
    i2c_master_write_byte(cmd, 0x06, true);  // Configuration register A
    i2c_master_write_byte(cmd, config_reg[0], true);  // Port A config
    i2c_master_write_byte(cmd, 0x07, true);  // Configuration register B
    i2c_master_write_byte(cmd, config_reg[1], true);  // Port B config
    i2c_master_stop(cmd);

    err = i2c_master_cmd_begin(I2C_NUM_0, cmd, 1000 / portTICK_PERIOD_MS);
    i2c_cmd_link_delete(cmd);

    if (err != ESP_OK) {
        // Handle error appropriately
        return;
    }
}

