void ATK_DNESP32S3::InitializeButtons() {
    // Configure the boot button GPIO as an input with internal pull-up resistor
    gpio_config_t io_conf = {};
    io_conf.intr_type = GPIO_INTR_NEGEDGE;  // Trigger on button press (active low)
    io_conf.mode = GPIO_MODE_INPUT;
    io_conf.pin_bit_mask = (1ULL << BOOT_BUTTON_PIN);
    io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
    io_conf.pull_up_en = GPIO_PULLUP_ENABLE;
    gpio_config(&io_conf);

    // Register a callback function to handle button press events
    gpio_install_isr_service(0);
    gpio_isr_handler_add(BOOT_BUTTON_PIN, ButtonPressISR, this);

    // Initialize button state tracking variables
    button_pressed_time = 0;
    button_is_pressed = false;
    button_state = BUTTON_IDLE;
}

