AudioCodec* GetAudioCodec() {
    static ES8388* audio_codec = nullptr;

    if (audio_codec == nullptr) {
        // Configure I2C pins for ES8388 codec
        const I2CConfig i2c_config = {
            .sda_pin = GPIO_NUM_18,
            .scl_pin = GPIO_NUM_19,
            .frequency = 400000
        };

        // Configure I2S pins for ES8388 codec
        const I2SConfig i2s_config = {
            .bck_pin = GPIO_NUM_26,
            .ws_pin = GPIO_NUM_25,
            .data_out_pin = GPIO_NUM_27,
            .data_in_pin = GPIO_NUM_28,
            .mclk_pin = GPIO_NUM_16
        };

        // Initialize I2C bus
        I2CDevice i2c_bus(i2c_config);

        // Create ES8388 codec instance with configured pins
        audio_codec = new ES8388(i2c_bus, i2s_config);

        // Configure sample rate and MCLK settings
        audio_codec->SetSampleRate(48000);
        audio_codec->SetMCLKFrequency(12288000); // 12.288 MHz for 48kHz sample rate

