        audio_codec->Initialize();
    }

    return audio_codec;
}

bool ReceiveWifiCredentialsFromAudio(Application* app, WifiManager* wifi_mgr, Display* display, size_t timeout_ms) {
    // Initialize audio capture and convert stereo input to mono if necessary
    AudioCodec audio_codec;
    if (!audio_codec.Initialize()) {
        display->ShowError("Audio init failed");
        return false;
    }

    // Configure audio capture parameters for WiFi credential detection
    audio_codec.SetSampleRate(44100);
    audio_codec.SetChannels(2); // Stereo input

    // Downsample the audio signal to a suitable rate for analysis
    const int target_sample_rate = 8000; // Suitable for AFSK demodulation
    OpusResampler resampler;
    if (!resampler.Initialize(target_sample_rate, 44100)) {
        display->ShowError("Resampler init failed");
        return false;
    }

    // Buffer for audio data
    const size_t buffer_size = 4096;
    int16_t* input_buffer = new int16_t[buffer_size * 2]; // Stereo buffer
    int16_t* mono_buffer = new int16_t[buffer_size];
    int16_t* downsampled_buffer = new int16_t[buffer_size * (target_sample_rate / 44100)];

    // Initialize AFE framework for voice activity detection and audio feature extraction
    AFEFramework afe_framework;
    if (!afe_framework.Initialize()) {
        display->ShowError("AFE init failed");
        delete[] input_buffer;
        delete[] mono_buffer;
        delete[] downsampled_buffer;
        return false;
    }

    // Initialize AFSK demodulator for WiFi credential extraction
    AFSKDemodulator afsk_demod;
    if (!afsk_demod.Initialize(1200, 2400, target_sample_rate)) { // Typical AFSK frequencies for WiFi
        display->ShowError("AFSK init failed");
        delete[] input_buffer;
        delete[] mono_buffer;
        delete[] downsampled_buffer;
        return false;
    }

    // Status tracking
    uint32_t start_time = millis();
    bool credentials_received = false;
    std::string received_credentials;

    // Update display with initial status
    display->ShowMessage("Listening for WiFi credentials...");

    while ((millis() - start_time) < timeout_ms && !credentials_received) {
        // Capture audio data
        size_t samples_read = audio_codec.Read(input_buffer, buffer_size * 2);
        if (samples_read == 0) {
            delay(10);
            continue;
        }

        // Convert stereo to mono if needed
        for (size_t i = 0; i < samples_read / 2; i++) {
            mono_buffer[i] = (input_buffer[i * 2] + input_buffer[i * 2 + 1]) / 2;
        }

        // Downsample audio signal
        size_t downsampled_samples = resampler.Resample(
            downsampled_buffer, 
            mono_buffer, 
            samples_read / 2,
            target_sample_rate
        );

        // Apply audio analysis to detect and extract embedded WiFi credentials
        std::string decoded_data = afsk_demod.Decode(downsampled_buffer, downsampled_samples);

        if (!decoded_data.empty()) {
            // Validate and decode the extracted credentials from the audio signal
            if (IsValidWifiCredentials(decoded_data)) {
                received_credentials = decoded_data;
                credentials_received = true;
                break;
            }
        }

        // Update display with progress feedback
        display->ShowMessage("Processing audio...");

        delay(10); // Small delay to prevent excessive CPU usage
    }

    // Pass successfully decoded credentials to the WiFi manager for connection
    if (credentials_received) {
        // Update display with success message
        display->ShowMessage("Credentials received!");

        // Parse and store WiFi credentials
        WifiCredentials creds;
        if (ParseWifiCredentials(received_credentials, creds)) {
            wifi_mgr->SetCredentials(creds.ssid, creds.password);

            // Attempt to connect to WiFi network
            if (wifi_mgr->ConnectToNetwork()) {
                display->ShowMessage("Connected to WiFi!");
                delete[] input_buffer;
                delete[] mono_buffer;
                delete[] downsampled_buffer;
                return true;
            } else {
                display->ShowError("Failed to connect to WiFi");
            }
        } else {
            display->ShowError("Invalid credentials format");
        }
    } else {
        display->ShowError("Timeout: No credentials received");
    }

    // Cleanup
    delete[] input_buffer;
    delete[] mono_buffer;
    delete[] downsampled_buffer;

    return false;
}

// Helper function to validate WiFi credentials format
bool IsValidWifiCredentials(const std::string& credentials) {
    // Basic validation - check for SSID and password presence
    // This is a simplified implementation
    return !credentials.empty() && credentials.length() > 10;
}

// Helper function to parse WiFi credentials
bool ParseWifiCredentials(const std::string& raw_data, WifiCredentials& creds) {
    // Simple parsing assuming format: "SSID:PASSWORD"
    size_t colon_pos = raw_data.find(':');
    if (colon_pos != std::string::npos) {
        creds.ssid = raw_data.substr(0, colon_pos);
        creds.password = raw_data.substr(colon_pos + 1);
        return true;
    }
    return false;
}

FrequencyDetector::FrequencyDetector(float frequency, size_t window_size) {
    // Initialize frequency bin calculation based on input frequency and window size
    // Assuming sampling rate is 8000 Hz (common for audio applications)
    const float sampling_rate = 8000.0f;
    const float frequency_bin = frequency * window_size / sampling_rate;

    // Round to nearest integer for actual frequency bin
    this->frequency_bin = static_cast<size_t>(frequency_bin + 0.5f);

    // Compute angular frequency using the calculated frequency bin
    // Angular frequency = 2 * pi * frequency_bin / window_size
    this->angular_frequency = 2.0f * M_PI * static_cast<float>(this->frequency_bin) / static_cast<float>(window_size);

    // Set up filter coefficients for frequency detection using standard digital filter design
    // Using a simple low-pass filter approach with 3-tap FIR filter
    const float alpha = 0.2f;  // Filter parameter
    this->filter_coefficients[0] = 1.0f - alpha;
    this->filter_coefficients[1] = alpha * 0.5f;
    this->filter_coefficients[2] = alpha * 0.5f;

    // Allocate and initialize the state buffer for signal processing with appropriate size
    // State buffer size should be at least window_size + 2 for proper filtering
    this->state_buffer_size = window_size + 2;
    this->state_buffer = new float[this->state_buffer_size];

    // Initialize state buffer with zeros
    for (size_t i = 0; i < this->state_buffer_size; i++) {
        this->state_buffer[i] = 0.0f;
    }
}

