void FrequencyDetector::ProcessSample(float sample) {
    // Initialize state buffer if empty
    if (state_buffer_.size() < 2) {
        while (state_buffer_.size() < 2) {
            state_buffer_.push_back(0.0f);
        }
    }

    // Apply second-order IIR filter difference equation
    // y[n] = x[n] - filter_coefficient_ * state_buffer_[0] + state_buffer_[1]
    float output = sample - filter_coefficient_ * state_buffer_[0] + state_buffer_[1];

    // Update state buffer: shift elements and add new output
    // Move S[-1] to S[-2] position
    state_buffer_[1] = state_buffer_[0];
    // Add new output to S[-1] position
    state_buffer_[0] = output;
}

float FrequencyDetector::GetAmplitude() const {
    // Check if we have enough samples in the buffer
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    // Get the last two samples from the state buffer
    const float sample1 = state_buffer_[state_buffer_.size() - 1];
    const float sample2 = state_buffer_[state_buffer_.size() - 2];

    // Compute real and imaginary parts using precomputed cosine and sine coefficients
    // Assuming we have access to cos_coeff_ and sin_coeff_ members
    const float real_part = sample1 * cos_coeff_ + sample2 * sin_coeff_;
    const float imag_part = sample1 * sin_coeff_ - sample2 * cos_coeff_;

    // Calculate amplitude as sqrt(real^2 + imag^2)
    const float amplitude = sqrtf(real_part * real_part + imag_part * imag_part);

    // Normalize by half the window size
    const float normalized_amplitude = amplitude / (window_size_ * 0.5f);

    return normalized_amplitude;
}

AudioSignalProcessor::AudioSignalProcessor(size_t sample_rate, size_t bit_rate, size_t mark_freq, size_t space_freq, size_t audio_buffer_size)
    : sample_rate_(sample_rate),
      bit_rate_(bit_rate),
      mark_freq_(mark_freq),
      space_freq_(space_freq),
      audio_buffer_size_(audio_buffer_size) {

    // Validate that the sample rate is divisible by the bit rate and log a warning if not
    if (sample_rate % bit_rate != 0) {
        // Log warning message
        LOG_WARNING("Sample rate (%zu) is not divisible by bit rate (%zu)", 
                   sample_rate, bit_rate);
    }

    // Calculate and store the number of samples per bit for signal analysis
    samples_per_bit_ = sample_rate / bit_rate;

    // Initialize frequency detectors for mark and space tones using normalized frequency values
    // Normalized frequency = (frequency / sample_rate) * 2^16
    uint16_t mark_normalized_freq = static_cast<uint16_t>((static_cast<double>(mark_freq) / static_cast<double>(sample_rate)) * 65536.0);
    uint16_t space_normalized_freq = static_cast<uint16_t>((static_cast<double>(space_freq) / static_cast<double>(sample_rate)) * 65536.0);

    // Setup mark tone detector
    mark_detector_ = new FrequencyDetector(mark_normalized_freq, samples_per_bit_);

    // Setup space tone detector  
    space_detector_ = new FrequencyDetector(space_normalized_freq, samples_per_bit_);
}

