class AFSKDemodulator {
private:
    std::vector<float> audio_buffer_;
    std::vector<float> mark_tone_buffer_;
    std::vector<float> space_tone_buffer_;
    GoertzelState mark_state_;
    GoertzelState space_state_;
    int buffer_index_;
    int window_size_;

    // Helper function to initialize Goertzel state
    GoertzelState InitializeGoertzel(float target_freq, int N) {
        GoertzelState state;
        float omega = 2.0f * M_PI * target_freq / 8000.0f; // Assuming 8kHz sampling rate
        state.coeff = 2.0f * cosf(omega);
        state.q1 = 0.0f;
        state.q2 = 0.0f;
        return state;
    }

    // Helper function to apply Goertzel algorithm
    float ApplyGoertzel(const std::vector<float>& samples, GoertzelState& state) {
        float q0 = 0.0f;
        for (int i = 0; i < samples.size(); i++) {
            q0 = state.coeff * state.q1 - state.q2 + samples[i];
            state.q2 = state.q1;
            state.q1 = q0;
        }

        // Calculate magnitude squared
        float real = state.q1 - state.q2 * cosf(state.coeff);
        float imag = state.q2 * sinf(state.coeff);
        return real * real + imag * imag;
    }

public:
    AFSKDemodulator(int window_size) : 
        window_size_(window_size),
        buffer_index_(0) {

        // Initialize buffers
        audio_buffer_.resize(window_size_);
        mark_tone_buffer_.resize(window_size_);
        space_tone_buffer_.resize(window_size_);

        // Initialize Goertzel states for mark and space tones
        // Assuming typical FSK frequencies: mark = 2200Hz, space = 1200Hz
        // Assuming 8kHz sampling rate
        mark_state_ = InitializeGoertzel(2200.0f, window_size_);
        space_state_ = InitializeGoertzel(1200.0f, window_size_);
    }

    std::vector<float> ProcessAudioSamples(const std::vector<float>& samples) {
        std::vector<float> probabilities;

        // Process each incoming sample
        for (size_t i = 0; i < samples.size(); ++i) {
            // Add sample to circular buffer
            audio_buffer_[buffer_index_] = samples[i];
            buffer_index_ = (buffer_index_ + 1) % window_size_;

            // When we have a complete window, process it
            if (buffer_index_ == 0) {
                // Extract current window from buffer
                for (int j = 0; j < window_size_; ++j) {
                    mark_tone_buffer_[j] = audio_buffer_[(buffer_index_ + j) % window_size_];
                    space_tone_buffer_[j] = audio_buffer_[(buffer_index_ + j) % window_size_];
                }

                // Apply Goertzel algorithm to detect mark and space tones
                float mark_energy = ApplyGoertzel(mark_tone_buffer_, mark_state_);
                float space_energy = ApplyGoertzel(space_tone_buffer_, space_state_);

                // Calculate probability of mark tone presence
                // Simple threshold-based approach - could be enhanced with more sophisticated methods
                float total_energy = mark_energy + space_energy;
                float mark_probability = (total_energy > 0.0f) ? (mark_energy / total_energy) : 0.0f;

                // Clamp probability between 0 and 1
                mark_probability = std::max(0.0f, std::min(1.0f, mark_probability));

                probabilities.push_back(mark_probability);
            }
        }

        return probabilities;
    }
};

