void AudioDataBuffer(size_t max_byte_size, 
                     const std::vector<uint8_t>& start_marker, 
                     const std::vector<uint8_t>& end_marker, 
                     bool enable_checksum) {
    // Initialize buffer identifiers for start and end of transmission markers
    m_start_marker = start_marker;
    m_end_marker = end_marker;

    // Configure checksum validation settings for data integrity
    m_enable_checksum = enable_checksum;
    m_checksum = 0;

    // Reserve memory for bit-level data storage based on max byte size
    // Each byte will be expanded to 8 bits for bit-level processing
    m_bit_buffer.reserve(max_byte_size * 8);

    // Set up internal state tracking for incoming audio stream management
    m_buffer_size = max_byte_size;
    m_bytes_received = 0;
    m_bits_received = 0;
    m_state = BUFFER_STATE_IDLE;
    m_in_sync = false;
    m_data_ready = false;
}

unsigned char CalculateChecksum(const std::string& str) {
    unsigned int sum = 0;
    for (char c : str) {
        sum += static_cast<unsigned char>(c);
    }
    return static_cast<unsigned char>(sum % 256);
}

