void Backlight::OnTransitionTimer() {
    // Check if we have a valid transition timer
    if (transition_timer_ == nullptr) {
        return;
    }

    // Calculate the difference between current and target brightness
    int16_t diff = target_brightness_ - brightness_;

    // If we've reached the target brightness, stop the transition
    if (diff == 0) {
        // Stop the timer
        esp_timer_stop(transition_timer_);
        return;
    }

    // Determine the direction and apply step size
    if (diff > 0) {
        // Increasing brightness
        brightness_ += (diff > step_) ? step_ : diff;
    } else {
        // Decreasing brightness
        brightness_ -= (abs(diff) > step_) ? step_ : abs(diff);
    }

    // Ensure brightness stays within valid range
    if (brightness_ > 255) {
        brightness_ = 255;
    } else if (brightness_ < 0) {
        brightness_ = 0;
    }

    // Apply the new brightness to hardware
    SetBrightnessImpl(brightness_);

    // Check if we've reached the target
    if (brightness_ == target_brightness_) {
        // Stop the timer as transition is complete
        esp_timer_stop(transition_timer_);
    }
}

