PwmBacklight::PwmBacklight(gpio_num_t gpio_num, bool inverted, uint32_t frequency)
    : gpio_num_(gpio_num), inverted_(inverted), frequency_(frequency) {

    // Step 1: Validate GPIO pin compatibility with LEDC peripheral for backlight
    if (gpio_num < 0 || gpio_num >= GPIO_NUM_MAX) {
        ESP_LOGE(TAG, "Invalid GPIO number: %d", gpio_num);
        return;
    }

    // Check if GPIO supports LEDC functionality (basic check)
    if (gpio_num == GPIO_NUM_0 || gpio_num == GPIO_NUM_1 || 
        gpio_num == GPIO_NUM_3 || gpio_num == GPIO_NUM_5 ||
        gpio_num == GPIO_NUM_12 || gpio_num == GPIO_NUM_13 ||
        gpio_num == GPIO_NUM_14 || gpio_num == GPIO_NUM_15 ||
        gpio_num == GPIO_NUM_16 || gpio_num == GPIO_NUM_17 ||
        gpio_num == GPIO_NUM_18 || gpio_num == GPIO_NUM_19 ||
        gpio_num == GPIO_NUM_20 || gpio_num == GPIO_NUM_21 ||
        gpio_num == GPIO_NUM_22 || gpio_num == GPIO_NUM_23 ||
        gpio_num == GPIO_NUM_25 || gpio_num == GPIO_NUM_26 ||
        gpio_num == GPIO_NUM_27 || gpio_num == GPIO_NUM_32 ||
        gpio_num == GPIO_NUM_33 || gpio_num == GPIO_NUM_34 ||
        gpio_num == GPIO_NUM_35 || gpio_num == GPIO_NUM_36 ||
        gpio_num == GPIO_NUM_37 || gpio_num == GPIO_NUM_38 ||
        gpio_num == GPIO_NUM_39) {
        // These pins support LEDC on ESP32-S3
    } else {
        ESP_LOGE(TAG, "GPIO %d does not support LEDC functionality", gpio_num);
        return;
    }

    // Step 2: Initialize the LEDC timer with specified frequency and resolution for PWM signal generation
    ledc_timer_config_t timer_conf = {};
    timer_conf.speed_mode = LEDC_LOW_SPEED_MODE;
    timer_conf.duty_resolution = LEDC_TIMER_10_BIT; // 10-bit resolution gives 1024 steps
    timer_conf.timer_num = LEDC_TIMER_0;
    timer_conf.freq_hz = frequency_;
    timer_conf.clk_cfg = LEDC_AUTO_CLK;

    esp_err_t err = ledc_timer_config(&timer_conf);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to configure LEDC timer: %s", esp_err_to_name(err));
        return;
    }

    // Step 3: Set up the LEDC channel to output PWM signal on the specified GPIO pin
    ledc_channel_config_t channel_conf = {};
    channel_conf.gpio_num = gpio_num;
    channel_conf.speed_mode = LEDC_LOW_SPEED_MODE;
    channel_conf.channel = LEDC_CHANNEL_0;
    channel_conf.intr_type = LEDC_INTR_DISABLE;
    channel_conf.timer_sel = LEDC_TIMER_0;
    channel_conf.duty = 0; // Start with zero duty cycle
    channel_conf.hpoint = 0;

    err = ledc_channel_config(&channel_conf);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to configure LEDC channel: %s", esp_err_to_name(err));
        return;
    }

    // Step 4: Configure PWM inversion and duty cycle based on input parameters
    inverted_ = inverted;
    duty_cycle_ = 0;

    // Step 5: Register the PWM backlight instance for system-wide control and monitoring
    register_backlight_instance(this);

    // Step 6: Implement error handling and logging for hardware initialization failures
    ESP_LOGI(TAG, "PWM Backlight initialized successfully on GPIO %d with frequency %u Hz", gpio_num, frequency_);
}

void PwmBacklight::set_duty_cycle(uint32_t duty) {
    if (duty > 1023) { // Max value for 10-bit resolution
        duty = 1023;
    }

    // Apply inversion if needed
    uint32_t actual_duty = inverted_ ? (1023 - duty) : duty;

    esp_err_t err = ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, actual_duty);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set LEDC duty cycle: %s", esp_err_to_name(err));
        return;
    }

    err = ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to update LEDC duty cycle: %s", esp_err_to_name(err));
        return;
    }

    duty_cycle_ = duty;
}

