std::string Board::GetSystemInfoJson() {
    cJSON *root = cJSON_CreateObject();
    if (root == NULL) {
        return "";
    }

    // Hardware information
    cJSON *hardware = cJSON_CreateObject();
    if (hardware != NULL) {
        // Chip model
        esp_chip_info_t chip_info;
        esp_chip_info(&chip_info);
        char chip_model[64];
        snprintf(chip_model, sizeof(chip_model), "ESP32-%s", 
                 chip_info.cores == 1 ? "SingleCore" : "DualCore");
        cJSON_AddStringToObject(hardware, "chip_model", chip_model);

        // Flash size
        size_t flash_size;
        if (esp_flash_get_size(NULL, &flash_size) == ESP_OK) {
            cJSON_AddNumberToObject(hardware, "flash_size_bytes", flash_size);
        }

        // MAC address
        uint8_t mac[6];
        if (esp_efuse_mac_get_default(mac) == ESP_OK) {
            char mac_str[18];
            snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
                     mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
            cJSON_AddStringToObject(hardware, "mac_address", mac_str);
        }

        cJSON_AddItemToObject(root, "hardware", hardware);
    }

    // Application metadata
    cJSON *application = cJSON_CreateObject();
    if (application != NULL) {
        // Version info
        const esp_app_desc_t *app_desc = esp_app_get_description();
        if (app_desc != NULL) {
            cJSON_AddStringToObject(application, "name", app_desc->project_name);
            cJSON_AddStringToObject(application, "version", app_desc->version);
            cJSON_AddStringToObject(application, "compile_time", app_desc->date);
        }

        cJSON_AddItemToObject(root, "application", application);
    }

    // Runtime information
    cJSON *runtime = cJSON_CreateObject();
    if (runtime != NULL) {
        // Minimum free heap size
        size_t min_free_heap = esp_get_minimum_free_heap_size();
        cJSON_AddNumberToObject(runtime, "min_free_heap_bytes", min_free_heap);

        // Current free heap size
        size_t free_heap = esp_get_free_heap_size();
        cJSON_AddNumberToObject(runtime, "free_heap_bytes", free_heap);

        cJSON_AddItemToObject(root, "runtime", runtime);
    }

    // Unique identifiers
    cJSON *identifiers = cJSON_CreateObject();
    if (identifiers != NULL) {
        // UUID
        std::string uuid = GetUuid();
        cJSON_AddStringToObject(identifiers, "uuid", uuid.c_str());

        cJSON_AddItemToObject(root, "identifiers", identifiers);
    }

    // Partition table data (basic info)
    cJSON *partitions = cJSON_CreateObject();
    if (partitions != NULL) {
        // We could add more detailed partition info here if needed
        cJSON_AddStringToObject(partitions, "status", "not_implemented");
        cJSON_AddItemToObject(root, "partitions", partitions);
    }

    // Convert to string
    char *json_string = cJSON_Print(root);
    std::string result;

    if (json_string != NULL) {
        result = json_string;
        free(json_string);
    }

    cJSON_Delete(root);
    return result;
}

void AdcButton(const button_adc_config_t &config) {
    // Initialize ADC button configuration and validate input parameters
    if (config.adc_channel >= ADC_CHANNEL_MAX || config.adc_channel < 0) {
        return; // Invalid ADC channel
    }

    if (config.threshold_low >= config.threshold_high) {
        return; // Invalid threshold range
    }

    // Register long press and short press handlers with IoT button framework
    // Configure button press detection with 2-second long press threshold
    button_config_t button_config = {
        .long_press_time_ms = 2000,  // 2 seconds long press
        .short_press_time_ms = 500,  // 500ms short press
        .press_handler = nullptr,
        .release_handler = nullptr,
        .long_press_handler = nullptr
    };

    // Create and store ADC button device handle for future use
    adc_button_handle_t adc_button_handle = nullptr;

    // Initialize ADC button device with provided configuration
    adc_button_handle = adc_button_create(config.adc_channel, 
                                        config.threshold_low, 
                                        config.threshold_high);

    if (adc_button_handle == nullptr) {
        return; // Failed to create ADC button
    }

    // Register with IoT button framework
    button_handle_t button_handle = button_create(&button_config);
    if (button_handle == nullptr) {
        adc_button_destroy(adc_button_handle);
        return; // Failed to create button
    }

    // Associate ADC button with IoT button framework
    button_set_adc_source(button_handle, adc_button_handle);

    // Store the button handle for later use
    g_adc_button_handles[g_adc_button_count] = button_handle;
    g_adc_button_count++;
}

Button::Button(gpio_num_t gpio_num, bool active_low, uint16_t short_press_threshold, uint16_t long_press_threshold, bool enable_power_save) {
    // Step 1: Initialize GPIO pin for button input with specified electrical polarity
    gpio_config_t io_conf = {};
    io_conf.pin_bit_mask = (1ULL << gpio_num);
    io_conf.mode = GPIO_MODE_INPUT;
    io_conf.pull_up_en = GPIO_PULLUP_ENABLE;
    io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
    io_conf.intr_type = GPIO_INTR_POSEDGE; // Default to rising edge interrupt

    // Configure GPIO based on active low setting
    if (active_low) {
        io_conf.pull_up_en = GPIO_PULLUP_DISABLE;
        io_conf.pull_down_en = GPIO_PULLDOWN_ENABLE;
        io_conf.intr_type = GPIO_INTR_NEGEDGE; // Falling edge for active-low buttons
    }

    gpio_config(&io_conf);

    // Store button configuration
    this->gpio_num = gpio_num;
    this->active_low = active_low;
    this->short_press_threshold = short_press_threshold;
    this->long_press_threshold = long_press_threshold;
    this->power_save_enabled = enable_power_save;

    // Step 2: Set up timing thresholds for short and long press detection
    // These values are already stored in member variables

    // Step 3: Configure power-saving behavior for the button device
    if (enable_power_save) {
        // Enable power-saving mode - typically involves disabling interrupts 
        // or putting the button handler into a low-power state when not active
        gpio_set_direction(gpio_num, GPIO_MODE_INPUT);
        // Additional power-saving configurations would go here
    } else {
        // Normal operation mode
        gpio_set_direction(gpio_num, GPIO_MODE_INPUT);
    }

    // Step 4: Register the button with the system's input handling framework
    // This assumes there's a global input dispatcher or manager
    InputEventDispatcher::getInstance()->registerDevice(this);
}

