void WifiBoard::StartNetwork() {
    auto display = Board::GetInstance().GetDisplay();

    // Initialize WiFi manager with predefined SSID prefix and language
    // Assuming there's a WiFiManager class available
    WiFiManager::GetInstance().SetSSIDPrefix("MyDevice_");
    WiFiManager::GetInstance().SetLanguage("en");

    // Set up unified event callback to handle various WiFi events
    Board::GetInstance().SetNetworkEventCallback([](NetworkEvent event, const std::string& data) {
        switch (event) {
            case NetworkEvent::Scanning:
                ESP_LOGI("WifiBoard", "WiFi scanning...");
                break;
            case NetworkEvent::Connecting:
                ESP_LOGI("WifiBoard", "Connecting to network: %s", data.c_str());
                break;
            case NetworkEvent::Connected:
                ESP_LOGI("WifiBoard", "Connected to network: %s", data.c_str());
                break;
            case NetworkEvent::Disconnected:
                ESP_LOGI("WifiBoard", "Disconnected from network");
                break;
            case NetworkEvent::WifiConfigModeEnter:
                ESP_LOGI("WifiBoard", "Entering WiFi configuration mode");
                break;
            case NetworkEvent::WifiConfigModeExit:
                ESP_LOGI("WifiBoard", "Exiting WiFi configuration mode");
                break;
            default:
                ESP_LOGI("WifiBoard", "WiFi event: %d", static_cast<int>(event));
                break;
        }
    });

    // Attempt to connect to a known WiFi network
    // Check if we have saved credentials
    Settings settings("wifi");
    std::string ssid = settings.GetString("ssid", "");
    std::string password = settings.GetString("password", "");

    if (!ssid.empty() && !password.empty()) {
        // Try to connect with saved credentials
        display->SetStatus(Lang::Strings::CONNECTING);
        WiFiManager::GetInstance().Connect(ssid, password);
    } else {
        // Enter configuration mode since no saved credentials exist
        display->SetStatus(Lang::Strings::CONFIG_MODE);
        WiFiManager::GetInstance().EnterConfigMode();
    }
}

