void WifiBoard::TryWifiConnect() {
    // Check for stored WiFi SSID credentials in persistent storage
    std::vector<WifiCredentials> stored_credentials = GetStoredWifiCredentials();

    if (!stored_credentials.empty()) {
        // Attempt to connect to WiFi using retrieved SSID and password
        for (const auto& cred : stored_credentials) {
            ESP_LOGI(TAG, "Attempting to connect to WiFi network: %s", cred.ssid.c_str());

            // Start the network connection process
            StartNetwork();

            // Wait a bit for connection attempt
            vTaskDelay(5000 / portTICK_PERIOD_MS);

            // Check if we're connected (this would typically be handled via events)
            // For now, we'll assume the connection attempt is made
            break; // Try first credential only for simplicity in this implementation
        }
    } else {
        // If no credentials exist, delay briefly before entering configuration mode
        ESP_LOGW(TAG, "No WiFi credentials found. Entering configuration mode.");
        vTaskDelay(1000 / portTICK_PERIOD_MS);

        // Initiate WiFi configuration mode to allow user to set up new network
        StartWifiConfigurationMode();
