void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string& event_data) {
    switch (event) {
        case NetworkEvent::kConnected: {
            // Update internal state flag
            is_connected_ = true;
            is_config_mode_ = false;

            // Stop any active timers
            if (reconnect_timer_) {
                reconnect_timer_->Stop();
            }

            // Release provisioning resources
            if (provisioning_resource_) {
                provisioning_resource_->Release();
                provisioning_resource_ = nullptr;
            }

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, event_data);
            }
            break;
        }

        case NetworkEvent::kDisconnected: {
            // Update internal state flag
            is_connected_ = false;

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, event_data);
            }
            break;
        }

        case NetworkEvent::kScanning: {
            // Update internal state flag
            is_scanning_ = true;

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, event_data);
            }
            break;
        }

        case NetworkEvent::kScanComplete: {
            // Update internal state flag
            is_scanning_ = false;

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, event_data);
            }
            break;
        }

        case NetworkEvent::kConfigModeEntered: {
            // Update internal state flag
            is_config_mode_ = true;

            // Stop any active timers
            if (reconnect_timer_) {
                reconnect_timer_->Stop();
            }

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, event_data);
            }
            break;
        }

        case NetworkEvent::kConfigModeExited: {
            // Update internal state flag
            is_config_mode_ = false;

            // Trigger reconnection attempt
            if (should_reconnect_) {
                StartReconnectionAttempt();
            }

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, event_data);
            }
            break;
        }

        default: {
            // Handle unknown events
            if (network_callback_) {
                network_callback_(event, event_data);
            }
            break;
        }
    }
}

void OnWifiConnectTimeout(void *) {
    // Step 1: Stop the current WiFi station mode to terminate the ongoing connection attempt
    // Assuming there's a WiFi manager with a method to stop station mode
    if (wifi_manager != nullptr) {
        wifi_manager->StopStationMode();
    }

    // Step 2: Transition the device state to configuration mode to allow user reconfiguration
    // Assuming there's a device state manager for handling state transitions
    if (device_state_manager != nullptr) {
        device_state_manager->SetState(DeviceState::CONFIGURATION_MODE);
    }

    // Step 3: Initiate the configuration mode interface for network re-setup
    // Assuming there's a configuration UI module that can be activated
    if (config_ui_module != nullptr) {
        config_ui_module->ActivateConfigurationMode();
    }
}

