const char* WifiBoard::GetNetworkStateIcon() {
    // Check if device is in configuration mode (AP mode)
    auto network = GetNetwork();
    if (network == nullptr) {
        return nullptr;
    }

    // Get current network state
    auto state = network->GetConnectionState();

    // Check if in configuration mode
    if (state == NetworkInterface::ConnectionState::CONFIG_MODE) {
        return FONT_AWESOME_WIFI_ACCESS_POINT;  // Or similar icon for config mode
    }

    // Check connection status
    switch (state) {
        case NetworkInterface::ConnectionState::DISCONNECTED:
            return FONT_AWESOME_WIFI_SLASH;  // Icon for disconnected

        case NetworkInterface::ConnectionState::CONNECTED: {
            // Get signal strength
            int signal_strength = network->GetSignalStrength();

            // Classify signal strength into categories
            if (signal_strength >= -50) {
                // Strong signal
                return FONT_AWESOME_WIFI;  // Full signal icon
            } else if (signal_strength >= -70) {
                // Fair signal
                return FONT_AWESOME_WIFI_HALF;  // Half signal icon
            } else {
                // Weak signal
                return FONT_AWESOME_WIFI_QUARTER;  // Low signal icon
            }
        }

        default:
            return FONT_AWESOME_WIFI_SLASH;  // Default to disconnected icon
    }
}

