std::string WifiBoard::GetBoardJson() {
    std::string json = "{";

    // Initialize JSON object with board type and name
    json += R"("type":")" + GetBoardType() + R"(",)";
    json += R"("name":")" + GetBoardType() + R"(",)";

    // Retrieve and add MAC address to the JSON object
    json += R"("mac_address":")" + SystemInfo::GetMacAddress() + R"(",)";

    // Conditionally include Wi-Fi details if not in configuration mode
    auto network = GetNetwork();
    if (network && !network->IsInConfigurationMode()) {
        // Add Wi-Fi info like SSID, RSSI, channel, IP when not in config mode
        std::string ssid = network->GetSsid();
        if (!ssid.empty()) {
            json += R"("ssid":")" + ssid + R"(",)";
        }

        int rssi = network->GetRssi();
        json += R"("rssi":)" + std::to_string(rssi) + R"(,)";

        int channel = network->GetChannel();
        json += R"("channel":)" + std::to_string(channel) + R"(,)";

        std::string ip_address = network->GetIpAddress();
        if (!ip_address.empty()) {
            json += R"("ip_address":")" + ip_address + R"(",)";
        }
    }

    // Remove trailing comma if present
    if (json.back() == ',') {
        json.pop_back();
    }

    json += "}";
    return json;
}

