void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level) {
    // Map generic power save levels to Wi-Fi specific power save settings
    WifiPowerSaveMode wifi_power_save_mode;

    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            wifi_power_save_mode = WifiPowerSaveMode::PS_MIN_MODEM;
            break;
        case PowerSaveLevel::BALANCED:
            wifi_power_save_mode = WifiPowerSaveMode::PS_MAX_MODEM;
            break;
        case PowerSaveLevel::PERFORMANCE:
            wifi_power_save_mode = WifiPowerSaveMode::PS_NONE;
            break;
        default:
            wifi_power_save_mode = WifiPowerSaveMode::PS_NONE;
            break;
    }

    // Retrieve the Wi-Fi manager instance to apply the power save level configuration
    auto& wifi_manager = WifiManager::GetInstance();

    // Apply the mapped Wi-Fi power save level using the Wi-Fi manager's API
    wifi_manager.SetPowerSaveMode(wifi_power_save_mode);
}

