std::string WifiBoard::GetDeviceStatusJson() {
    // Initialize JSON object
    JsonObject json = jsonBuffer.createObject();

    // Retrieve audio speaker volume level from AudioCodec HAL
    auto audio_codec = GetAudioCodec();
    if (audio_codec) {
        int volume = audio_codec->GetOutputVolume();
        json["audio_volume"] = volume;
    }

    // Fetch screen brightness and theme from Display HAL
    auto display = GetDisplay();
    if (display) {
        auto backlight = GetBacklight();
        if (backlight) {
            json["screen_brightness"] = backlight->GetBrightness();
        }

        // Get theme information
        auto theme = display->GetTheme();
        if (theme) {
            json["screen_theme"] = theme->GetName();
        }
    }

    // Collect battery level and charging state via Board HAL's power management interface
    int battery_level = 0;
    bool charging = false;
    bool discharging = false;
    if (GetBatteryLevel(battery_level, charging, discharging)) {
        json["battery_level"] = battery_level;
        json["battery_charging"] = charging;
        json["battery_discharging"] = discharging;
    }

    // Obtain WiFi network details including SSID and signal strength from NetworkInterface HAL
    auto network = GetNetwork();
    if (network) {
        std::string ssid = network->GetSsid();
        if (!ssid.empty()) {
            json["wifi_ssid"] = ssid;
        }

        int signal_strength = network->GetSignalStrength();
        json["wifi_signal_strength"] = signal_strength;
    }

    // Include chip temperature reading from the system's thermal monitoring module
    float chip_temp = 0.0f;
    if (GetTemperature(chip_temp)) {
        json["chip_temperature"] = chip_temp;
    }

    // Convert JSON object to string
    String json_string;
    json.printTo(json_string);
    return json_string.c_str();
}

void Display::SetChatMessage(const char* role, const char* message) {
    // Input validation - check for null pointers
    if (role == nullptr || message == nullptr) {
        return;
    }

    // Log the chat message to console with role prefix
    // This serves as a debugging aid during development/testing
    std::cout << "[CHAT][" << role << "] " << message << std::endl;
}

void Display::SetTheme(Theme *theme) {
    // Validate the theme pointer and handle null case
    if (theme == nullptr) {
        return;
    }

    // Update the internal theme reference in the Display class
    current_theme_ = theme;

    // Persist the theme name to the settings storage
    Settings::GetInstance()->SaveThemeName(theme->GetName());

    // Trigger UI refresh to apply the new theme
    ui_renderer_->Refresh();
}

