    // Initialize the LED color configuration and acquire the thread-safe mutex lock
    std::lock_guard<std::mutex> lock(mutex_);

    // Stop any active blink timer to ensure immediate LED activation
    if (blink_timer_ != nullptr) {
        esp_timer_stop(blink_timer_);
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
    }

    // Update the LED strip with the configured RGB color values
    // Using the existing SetColor method to set the color
    SetColor(r_, g_, b_);

    // Refresh the LED strip to display the new color immediately
    if (led_strip_ != nullptr) {
        led_strip_refresh(led_strip_);
    }

    // Release the mutex after completing the turn-on operation
    // Mutex is automatically released when lock_guard goes out of scope
