void SingleLed::TurnOff() {
    // Acquire the mutex lock to ensure thread-safe execution
    std::lock_guard<std::mutex> lock(mutex_);

    // Check if the LED strip is initialized to prevent null pointer access
    if (led_strip_ == nullptr) {
        return;
    }

    // Stop any active blinking timer to halt LED animation
    if (blink_timer_ != nullptr) {
        esp_timer_stop(blink_timer_);
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
    }

    // Stop any active blinking task
    if (blink_task_ != nullptr) {
        vTaskDelete(blink_task_);
        blink_task_ = nullptr;
    }

    // Clear the LED strip state to disable the LED
    // Set all pixels to off (black)
    if (led_strip_) {
        led_strip_clear(led_strip_);
    }
}

#include <freertos/FreeRTOS.h>
#include <freertos/timers.h>
#include "single_led.h"

// Global variables for the blinking task
static TimerHandle_t blink_timer = NULL;
static int led_pin = -1;
static int blink_count = 0;
static int interval_ms = 0;
static int current_blink = 0;

// Timer callback function to toggle LED state
static void BlinkTimerCallback(TimerHandle_t xTimer)
{
    // Toggle the LED state
    if (led_pin >= 0) {
        gpio_set_level(led_pin, !gpio_get_level(led_pin));
    }

    current_blink++;

    // Stop timer when all blinks are completed
    if (current_blink >= blink_count * 2) { // Each blink has ON and OFF states
        xTimerStop(blink_timer, 0);
        xTimerDelete(blink_timer, 0);
        blink_timer = NULL;
        current_blink = 0;
    }
}

void StartBlinkTask(int pin, int num_blinks)
{
    // Check if the LED strip is initialized before proceeding with the blinking task
    if (!is_led_strip_initialized()) {
        return;
    }

    // Store LED pin and blink parameters
    led_pin = pin;
    blink_count = num_blinks;
    interval_ms = 500; // Default interval of 500ms

    // Configure timer parameters
    // For a complete blink cycle (on + off), we need two intervals
    // But since we're using a timer to toggle, we'll set interval to half the cycle time
    interval_ms = 500; // 500ms interval for each state change

    // Create and start a periodic FreeRTOS timer to handle the blinking sequence
    blink_timer = xTimerCreate(
        "LED_Blink_Timer",           // Timer name
        pdMS_TO_TICKS(interval_ms),  // Timer period
        pdTRUE,                      // Auto-reload
        (void*)0,                    // Timer ID
        BlinkTimerCallback           // Callback function
    );

    if (blink_timer != NULL) {
        // Start the timer
        if (xTimerStart(blink_timer, 0) != pdPASS) {
            // Handle timer start failure
            xTimerDelete(blink_timer, 0);
            blink_timer = NULL;
        }
    }
}

