void SingleLed::OnBlinkTimer() {
    // Acquire mutex to safely access LED state within the timer handler
    std::lock_guard<std::mutex> lock(mutex_);

    // Toggle the LED state (on/off) and decrement the blink countdown
    if (blink_counter_ > 0) {
        // Toggle LED state - for single LED, we can just turn it on/off
        if (blink_counter_ % 2 == 0) {
            // Turn off
            led_strip_clear(led_strip_);
        } else {
            // Turn on with default color (white)
            led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
        }
        blink_counter_--;

        // Check if the blink sequence is complete and stop the timer if so
        if (blink_counter_ <= 0) {
            // Stop the timer
            esp_timer_stop(blink_timer_);
            // Optionally turn off the LED when done
            led_strip_clear(led_strip_);
        } else {
            // Restart the timer for next blink
            esp_timer_start_once(blink_timer_, blink_interval_ms_ * 1000);
        }
    } else {
        // Stop the timer if no more blinks
        esp_timer_stop(blink_timer_);
    }
}

