void SingleLed::OnStateChanged() {
    // Get the current device state from the global state machine
    DeviceState current_state = state_machine_.GetState();

    // Lock the mutex to ensure thread safety
    std::lock_guard<std::mutex> lock(mutex_);

    // Map device states to LED colors and behaviors
    switch (current_state) {
        case kDeviceStateUnknown:
        case kDeviceStateIdle:
            // Solid blue for idle/standby
            SetColor(0, 0, 255);  // Blue
            TurnOn();
            break;

        case kDeviceStateConnecting:
            // Fast blinking cyan for connecting
            SetColor(0, 255, 255);  // Cyan
            StartContinuousBlink(250);  // 250ms blink interval
            break;

        case kDeviceStateListening:
            // Slow blinking green for listening
            SetColor(0, 255, 0);  // Green
            StartContinuousBlink(500);  // 500ms blink interval
            break;

        case kDeviceStateSpeaking:
            // Solid green for speaking
            SetColor(0, 255, 0);  // Green
            TurnOn();
            break;

        case kDeviceStateWifiConfiguring:
            // Fast blinking yellow for Wi-Fi configuration
            SetColor(255, 255, 0);  // Yellow
            StartContinuousBlink(100);  // 100ms blink interval
            break;

        case kDeviceStateStarting:
            // Fast blinking white for starting
            SetColor(255, 255, 255);  // White
            StartContinuousBlink(150);  // 150ms blink interval
            break;

        case kDeviceStateUpgrading:
            // Fast blinking purple for upgrading
            SetColor(255, 0, 255);  // Purple
            StartContinuousBlink(200);  // 200ms blink interval
            break;

        case kDeviceStateActivating:
            // Fast blinking orange for activating
            SetColor(255, 165, 0);  // Orange
            StartContinuousBlink(300);  // 300ms blink interval
            break;

        default:
            // Default to off for unknown states
            TurnOff();
            break;
    }
}

MqttProtocol::MqttProtocol() {
    // Initialize the MQTT protocol event group for synchronization between tasks
    mqtt_event_group = xEventGroupCreate();
    if (mqtt_event_group == NULL) {
        ESP_LOGE(TAG, "Failed to create MQTT event group");
        return;
    }

    // Set up the reconnect timer to periodically attempt MQTT reconnection
    const esp_timer_create_args_t reconnect_timer_args = {
        .callback = &MqttProtocol::reconnect_timer_callback,
        .name = "mqtt_reconnect_timer",
        .arg = this,
        .skip_unhandled_events = true
    };

    esp_err_t err = esp_timer_create(&reconnect_timer_args, &reconnect_timer);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create MQTT reconnect timer: %s", esp_err_to_name(err));
        return;
    }

    // Register the MQTT reconnect callback with the application task scheduler
    // This ensures that reconnection attempts are scheduled properly
    reconnect_task_handle = xTaskCreate(
        MqttProtocol::reconnect_task_handler,
        "mqtt_reconnect_task",
        4096,
        this,
        configMAX_PRIORITIES - 1,
        NULL
    );

    if (reconnect_task_handle == NULL) {
        ESP_LOGE(TAG, "Failed to create MQTT reconnect task");
        return;
    }

    // Ensure the reconnect logic respects current device state and avoids interrupting active operations
    // We'll use the event group to signal when it's safe to reconnect
    // The reconnection process will check device state before attempting connection

    // Initialize the MQTT client with default settings
    mqtt_client_config_t mqtt_cfg = MQTT_CLIENT_CONFIG_DEFAULT();
    mqtt_client = esp_mqtt_client_init(&mqtt_cfg);

    if (mqtt_client == NULL) {
        ESP_LOGE(TAG, "Failed to initialize MQTT client");
        return;
    }

    // Set up MQTT event handler
    esp_mqtt_client_register_event(mqtt_client, ESP_EVENT_ANY_ID, mqtt_event_handler, this);

    // Start the reconnect timer with initial delay
    err = esp_timer_start_periodic(reconnect_timer, RECONNECT_INTERVAL_MS * 1000);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start MQTT reconnect timer: %s", esp_err_to_name(err));
    }
}

MqttProtocol::~MqttProtocol() {
    // Step 1: Stop and delete the MQTT reconnect timer to prevent further retry attempts
    if (reconnect_timer_ != nullptr) {
        xTimerStop(reconnect_timer_, 0);
        xTimerDelete(reconnect_timer_, 0);
        reconnect_timer_ = nullptr;
    }

    // Step 2: Reset UDP and MQTT resources to release associated buffers and connections
    if (udp_socket_ != -1) {
        close(udp_socket_);
        udp_socket_ = -1;
    }

    if (mqtt_client_ != nullptr) {
        // Disconnect MQTT client if connected
        if (mqtt_client_->isConnected()) {
            mqtt_client_->disconnect();
        }
        // Cleanup MQTT client resources
        delete mqtt_client_;
        mqtt_client_ = nullptr;
    }

    // Step 3: Release the event group used for synchronization and signaling
    if (event_group_ != nullptr) {
        vEventGroupDelete(event_group_);
        event_group_ = nullptr;
    }

    // Step 4: Mark the MQTT protocol instance as inactive to prevent pending tasks from executing
    is_active_ = false;
}

bool StartMqttClient(bool forceReconnect = false) {
    // Initialize MQTT client instance with configuration settings
    if (!mqtt_client_) {
        // Create MQTT client instance
        mqtt_client_ = new MqttClient();

        // Get broker configuration from settings
        std::string broker_endpoint = config_manager_->GetBrokerEndpoint();
        int broker_port = config_manager_->GetBrokerPort();
        std::string client_id = config_manager_->GetClientId();
        std::string username = config_manager_->GetUsername();
        std::string password = config_manager_->GetPassword();

        // Configure MQTT client with broker settings
        mqtt_client_->setServer(broker_endpoint.c_str(), broker_port);
        mqtt_client_->setClientId(client_id.c_str());
        mqtt_client_->setCredentials(username.c_str(), password.c_str());
    }

    // Register event handlers for connection, disconnection, and message reception
    mqtt_client_->onConnect([this](bool sessionPresent) {
        HandleMqttConnected(sessionPresent);
    });

    mqtt_client_->onDisconnect([this](AsyncMqttClientDisconnectReason reason) {
        HandleMqttDisconnected(reason);
    });

    mqtt_client_->onMessage([this](char* topic, char* payload, AsyncMqttClientMessageProperties properties, size_t len, size_t index, size_t total) {
        HandleIncomingMessage(topic, payload, len);
    });

    // Connect to MQTT broker
    bool connected = mqtt_client_->connect();

    if (connected) {
        // Subscribe to required topics
        SubscribeToTopics();

        // Log successful connection
        LOG_INFO("MQTT client connected successfully");
        return true;
    } else {
        // Log connection failure
        LOG_ERROR("Failed to connect MQTT client");
        return false;
    }
}

private:
void HandleMqttConnected(bool sessionPresent) {
    LOG_INFO("MQTT client connected");

    // Trigger session management if needed
    if (!sessionPresent) {
        // Initialize new session
        InitializeNewSession();
    }

    // Re-subscribe to all topics
    SubscribeToTopics();
}

void HandleMqttDisconnected(AsyncMqttClientDisconnectReason reason) {
    LOG_WARN("MQTT client disconnected, reason: %d", static_cast<int>(reason));

    // Schedule reconnect attempt
    ScheduleReconnect();
}

void HandleIncomingMessage(char* topic, char* payload, size_t len) {
    // Parse JSON payload
    StaticJsonDocument<512> doc;
    DeserializationError error = deserializeJson(doc, payload, len);

    if (error) {
        LOG_ERROR("Failed to parse JSON message: %s", error.c_str());
        return;
    }

    // Route message based on topic
    std::string topic_str(topic);

    if (topic_str.find("session") != std::string::npos) {
        HandleSessionMessage(doc);
    } else if (topic_str.find("audio") != std::string::npos) {
        HandleAudioChannelMessage(doc);
    } else {
        LOG_WARN("Unknown topic: %s", topic);
    }
}

void SubscribeToTopics() {
    // Subscribe to session management topics
    mqtt_client_->subscribe("session/control", 1);
    mqtt_client_->subscribe("session/status", 1);

    // Subscribe to audio channel topics
    mqtt_client_->subscribe("audio/channel/+/control", 1);
    mqtt_client_->subscribe("audio/channel/+/status", 1);

    LOG_INFO("Subscribed to MQTT topics");
}

void ScheduleReconnect() {
    // Schedule reconnect after delay
    reconnect_timer_ = new Timer();
    reconnect_timer_->once_ms(5000, [this]() {
        LOG_INFO("Attempting MQTT reconnect...");
        StartMqttClient(true);
    });
}

void InitializeNewSession() {
    // Initialize session management logic
    LOG_INFO("Initializing new session");
}

void HandleSessionMessage(const JsonDocument& doc) {
    // Process session-related JSON messages
    const char* action = doc["action"] | "";
    if (strcmp(action, "start") == 0) {
        // Start session logic
        LOG_INFO("Starting new session");
    } else if (strcmp(action, "end") == 0) {
        // End session logic
        LOG_INFO("Ending current session");
    }
}

void HandleAudioChannelMessage(const JsonDocument& doc) {
    // Process audio channel related JSON messages
    const char* channel = doc["channel"] | "";
    const char* action = doc["action"] | "";

    LOG_INFO("Audio channel message - Channel: %s, Action: %s", channel, action);

    // Implement audio channel control logic here
}

bool SendText(const std::string& message) {
    // Step 1: Validate the input text message and prepare MQTT publish payload
    if (message.empty()) {
        // Log error for empty message
        LOG_ERROR("Attempted to send empty text message");
        SetServerErrorState(true);
        return false;
    }

    // Prepare MQTT message payload from string input
    // Assuming we have access to MQTT client instance and predefined topic
    const std::string& topic = "system/text";  // Predefined MQTT topic

    // Step 2: Publish the text message to the predefined MQTT topic
    bool publish_success = mqtt_client_->Publish(topic, message);

    // Step 3: Handle the result of the publish operation
    if (publish_success) {
        return true;
    } else {
        // Log error and set server error state on failure
        LOG_ERROR("Failed to publish text message to MQTT topic: " + topic);
        SetServerErrorState(true);
        return false;
    }
}

