void MqttProtocol::CloseAudioChannel() {
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Reset the active UDP connection used for audio streaming
    if (udp_) {
        udp_.reset();
    }

    // Send a "goodbye" message to the MQTT server to notify session closure
    if (mqtt_ && !session_id_.empty()) {
        cJSON* root = cJSON_CreateObject();
        cJSON_AddStringToObject(root, "type", "goodbye");
        cJSON_AddStringToObject(root, "session_id", session_id_.c_str());

        char* json_string = cJSON_PrintUnformatted(root);
        if (json_string) {
            mqtt_->Publish(publish_topic_, json_string);
            cJSON_free(json_string);
        }
        cJSON_Delete(root);
    }

    // Clear session ID after sending goodbye message
    session_id_.clear();

    // Trigger the application callback to notify that the audio channel is closed
    if (on_audio_channel_closed_ != nullptr) {
        on_audio_channel_closed_();
    }
}

