std::string MqttProtocol::GetHelloMessage() {
    cJSON* root = cJSON_CreateObject();

    // Set message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Add device capabilities
    cJSON* capabilities = cJSON_CreateObject();
    cJSON_AddBoolToObject(capabilities, "aec", true);  // AEC support
    cJSON_AddBoolToObject(capabilities, "mcp", true);  // MCP support
    cJSON_AddItemToObject(root, "capabilities", capabilities);

    // Add audio parameters
    cJSON* audio = cJSON_CreateObject();
    cJSON_AddStringToObject(audio, "format", "pcm");  // Assuming PCM format
    cJSON_AddNumberToObject(audio, "sample_rate", 16000);  // Typical audio sample rate
    cJSON_AddNumberToObject(audio, "frame_duration", 20);  // 20ms frame duration
    cJSON_AddItemToObject(root, "audio", audio);

    // Add device metadata
    cJSON* device = cJSON_CreateObject();
    cJSON_AddStringToObject(device, "device_id", SystemInfo::GetMacAddress().c_str());
    cJSON_AddStringToObject(device, "client_id", Board::GetInstance().GetUuid().c_str());
    cJSON_AddStringToObject(device, "model", "ESP32-Audio-Device");  // Device model
    cJSON_AddStringToObject(device, "firmware_version", "1.0.0");  // Firmware version
    cJSON_AddItemToObject(root, "device", device);

    // Add status information
    cJSON* status = cJSON_CreateObject();
    cJSON_AddBoolToObject(status, "online", true);
    cJSON_AddNumberToObject(status, "battery_level", 100);  // Assuming full battery
    cJSON_AddItemToObject(root, "status", status);

    // Serialize to string
    char* json_string = cJSON_Print(root);
    std::string result = json_string;

    // Clean up
    free(json_string);
    cJSON_Delete(root);

    return result;
}

bool ParseServerHello(const cJSON *server_hello_json) {
    // Step 1: Parse the server hello JSON to extract UDP transport configuration
    const cJSON *udp_config = cJSON_GetObjectItem(server_hello_json, "udp");
    if (!udp_config || !cJSON_IsObject(udp_config)) {
        return false;
    }

    const cJSON *server_addr = cJSON_GetObjectItem(udp_config, "server_address");
    const cJSON *server_port = cJSON_GetObjectItem(udp_config, "port");
    const cJSON *encryption_key = cJSON_GetObjectItem(udp_config, "encryption_key");
    const cJSON *nonce = cJSON_GetObjectItem(udp_config, "nonce");

    if (!server_addr || !cJSON_IsString(server_addr) ||
        !server_port || !cJSON_IsNumber(server_port) ||
        !encryption_key || !cJSON_IsString(encryption_key) ||
        !nonce || !cJSON_IsString(nonce)) {
        return false;
    }

    // Extract server address and port
    std::string address = server_addr->valuestring;
    int port = server_port->valueint;

    // Step 2: Initialize AES encryption context using the extracted key and nonce
    std::string key_str = encryption_key->valuestring;
    std::string nonce_str = nonce->valuestring;

    // Convert hex string to bytes for AES key (assuming 16-byte key)
    std::vector<uint8_t> key(16);
    std::vector<uint8_t> iv(16);

    // Parse key from hex string
    for (size_t i = 0; i < 16 && i * 2 < key_str.length(); ++i) {
        uint8_t byte_val = 0;
        for (int j = 0; j < 2; ++j) {
            char c = key_str[i * 2 + j];
            byte_val <<= 4;
            if (c >= '0' && c <= '9') {
                byte_val |= c - '0';
            } else if (c >= 'a' && c <= 'f') {
                byte_val |= c - 'a' + 10;
            } else if (c >= 'A' && c <= 'F') {
                byte_val |= c - 'A' + 10;
            }
        }
        key[i] = byte_val;
    }

    // Parse nonce from hex string
    for (size_t i = 0; i < 16 && i * 2 < nonce_str.length(); ++i) {
        uint8_t byte_val = 0;
        for (int j = 0; j < 2; ++j) {
            char c = nonce_str[i * 2 + j];
            byte_val <<= 4;
            if (c >= '0' && c <= '9') {
                byte_val |= c - '0';
            } else if (c >= 'a' && c <= 'f') {
                byte_val |= c - 'a' + 10;
            } else if (c >= 'A' && c <= 'F') {
                byte_val |= c - 'A' + 10;
            }
        }
        iv[i] = byte_val;
    }

    // Initialize AES context
    aes_context aes_ctx;
    aes_setkey_enc(&aes_ctx, key.data(), 128);

    // Step 3: Retrieve and validate audio parameters
    const cJSON *audio_config = cJSON_GetObjectItem(server_hello_json, "audio");
    if (!audio_config || !cJSON_IsObject(audio_config)) {
        return false;
    }

    const cJSON *sample_rate = cJSON_GetObjectItem(audio_config, "sample_rate");
    const cJSON *frame_duration = cJSON_GetObjectItem(audio_config, "frame_duration");

    if (!sample_rate || !cJSON_IsNumber(sample_rate) ||
        !frame_duration || !cJSON_IsNumber(frame_duration)) {
        return false;
    }

    int sr = sample_rate->valueint;
    int fd = frame_duration->valueint;

    // Validate audio parameters
    if (sr <= 0 || fd <= 0) {
        return false;
    }

    // Step 4: Configure the UDP transport layer with parsed server details
    // Set up UDP transport with server address and port
    if (!udp_transport_.Configure(address.c_str(), port)) {
        return false;
    }

    // Set encryption context
    udp_transport_.SetEncryptionContext(&aes_ctx, iv.data());

    // Store audio parameters
    audio_sample_rate_ = sr;
    audio_frame_duration_ = fd;

    // Step 5: Signal successful processing of server hello
    server_hello_processed_ = true;

    return true;
}

int CharToHex(char c) {
    if (c >= '0' && c <= '9') {
        return c - '0';
    } else if (c >= 'A' && c <= 'F') {
        return c - 'A' + 10;
    } else if (c >= 'a' && c <= 'f') {
        return c - 'a' + 10;
    } else {
        return 0;
    }
}

std::string MqttProtocol::DecodeHexString(const std::string& hex_string) {
    std::string result;

    // Handle empty input
    if (hex_string.empty()) {
        return result;
    }

    // Process the string two characters at a time
    for (size_t i = 0; i < hex_string.length(); i += 2) {
        // Check if we have at least two characters left
        if (i + 1 >= hex_string.length()) {
            // Odd number of characters, skip the last one or treat as invalid
            // For this implementation, we'll skip incomplete pairs
            break;
        }

        char hex_char1 = hex_string[i];
        char hex_char2 = hex_string[i + 1];

        // Validate first character
        if (!isxdigit(hex_char1) || !isxdigit(hex_char2)) {
            // Invalid hex character found, return empty string or handle as needed
            return std::string();
        }

        // Convert hex characters to decimal values
        int val1 = 0, val2 = 0;

        if (hex_char1 >= '0' && hex_char1 <= '9') {
            val1 = hex_char1 - '0';
        } else if (hex_char1 >= 'a' && hex_char1 <= 'f') {
            val1 = hex_char1 - 'a' + 10;
        } else if (hex_char1 >= 'A' && hex_char1 <= 'F') {
            val1 = hex_char1 - 'A' + 10;
        }

        if (hex_char2 >= '0' && hex_char2 <= '9') {
            val2 = hex_char2 - '0';
        } else if (hex_char2 >= 'a' && hex_char2 <= 'f') {
            val2 = hex_char2 - 'a' + 10;
        } else if (hex_char2 >= 'A' && hex_char2 <= 'F') {
            val2 = hex_char2 - 'A' + 10;
        }

        // Combine the two hex digits into one byte
        unsigned char byte_val = static_cast<unsigned char>((val1 << 4) | val2);

        // Append to result
        result.push_back(static_cast<char>(byte_val));
    }

    return result;
}

void Protocol::SetError(const std::string& error_message) {
    // Thread-safe implementation using static mutex
    static std::mutex error_mutex;
    std::lock_guard<std::mutex> lock(error_mutex);

    // Use a static flag to ensure error handler is only called once
    static bool error_already_handled = false;
    if (error_already_handled) {
        return; // Prevent duplicate notifications
    }

    // Store the error message
    static std::string last_error_message;
    last_error_message = error_message;

    // Notify the registered error handler if one exists
    if (error_handler_ != nullptr) {
        error_handler_(last_error_message);
        error_already_handled = true;
    }
}

