void Protocol::SendAbortSpeaking(AbortReason reason) {
    // Create JSON object for abort message
    cJSON* json_root = cJSON_CreateObject();
    if (!json_root) {
        SetError("Failed to create JSON object for abort message");
        return;
    }

    // Add session ID to the JSON object
    cJSON* session_id_item = cJSON_CreateString(session_id_.c_str());
    if (session_id_item) {
        cJSON_AddItemToObject(json_root, "session_id", session_id_item);
    } else {
        cJSON_Delete(json_root);
        SetError("Failed to add session ID to JSON object");
        return;
    }

    // Add abort reason to the JSON object
    cJSON* reason_item = cJSON_CreateNumber(static_cast<int>(reason));
    if (reason_item) {
        cJSON_AddItemToObject(json_root, "reason", reason_item);
    } else {
        cJSON_Delete(json_root);
        SetError("Failed to add reason to JSON object");
        return;
    }

    // Convert JSON to string
    char* json_string = cJSON_PrintUnformatted(json_root);
    if (!json_string) {
        cJSON_Delete(json_root);
        SetError("Failed to serialize JSON to string");
        return;
    }

    // Send the JSON string through the communication channel
    SendText(json_string);

    // Clean up memory
    free(json_string);
    cJSON_Delete(json_root);
}

void SendWakeWordDetected(const std::string& wake_word) {
    // Step 1: Retrieve the current session context to populate session-related fields
    auto session_context = GetActiveSessionContext();

    // Step 2: Prepare the JSON message containing session ID, interaction type, state, and detected wake word
    nlohmann::json message;
    message["session_id"] = session_context.session_id;
    message["interaction_type"] = "wake_word_detection";
    message["state"] = "detected";
    message["wake_word"] = wake_word;
    message["timestamp"] = std::chrono::duration_cast<std::chrono::milliseconds>(
        std::chrono::system_clock::now().time_since_epoch()).count();

    // Step 3: Format the JSON message according to the protocol specification
    std::string json_string = message.dump();

    // Step 4: Send the formatted JSON message through the established communication channel
    SendProtocolMessage(json_string);
}

