    // Create JSON object for the message
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        return;
    }

    // Add session ID
    cJSON_AddStringToObject(root, "session_id", session_id_.c_str());

    // Add type
    cJSON_AddStringToObject(root, "type", "listen");

    // Add state
    cJSON_AddStringToObject(root, "state", "start");

    // Add listening mode based on enum value
    const char* mode_str = nullptr;
    switch (mode) {
        case kListeningModeAutoStop:
            mode_str = "auto";
            break;
        case kListeningModeManualStop:
            mode_str = "manual";
            break;
        case kListeningModeRealtime:
            mode_str = "realtime";
            break;
        default:
            mode_str = "unknown";
            break;
    }
    cJSON_AddStringToObject(root, "mode", mode_str);

    // Convert JSON object to string
    char* json_string = cJSON_Print(root);
    if (json_string) {
        // Send the JSON string via SendText
        SendText(json_string);
        // Free the allocated string
        free(json_string);
    }

    // Clean up the JSON object
    cJSON_Delete(root);
