void Protocol::SendStopListening() {
    // Create JSON object for stop listening message
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        SetError("Failed to create JSON object for stop listening message");
        return;
    }

    // Add session ID
    cJSON* session_id_item = cJSON_CreateString(session_id_.c_str());
    if (session_id_item) {
        cJSON_AddItemToObject(root, "session_id", session_id_item);
    }

    // Add message type
    cJSON* type_item = cJSON_CreateString("listen");
    if (type_item) {
        cJSON_AddItemToObject(root, "type", type_item);
    }

    // Add state
    cJSON* state_item = cJSON_CreateString("stop");
    if (state_item) {
        cJSON_AddItemToObject(root, "state", state_item);
    }

    // Convert JSON to string
    char* json_string = cJSON_PrintUnformatted(root);
    if (!json_string) {
        cJSON_Delete(root);
        SetError("Failed to serialize JSON for stop listening message");
        return;
    }

    // Send the JSON message
    SendText(json_string);

    // Clean up
    free(json_string);
    cJSON_Delete(root);
}

