bool Protocol::IsTimeout() const {
    // Get current timestamp
    auto current_time = std::chrono::steady_clock::now();

    // Get last message timestamp (assuming there's a member variable m_last_message_time)
    auto last_message_time = m_last_message_time;

    // Calculate time difference
    auto time_diff = std::chrono::duration_cast<std::chrono::seconds>(
        current_time - last_message_time);

    // Check if elapsed time exceeds 120 seconds timeout threshold
    if (time_diff.count() > 120) {
        // Log error message for channel timeout event
        LOG_ERROR("Channel has timed out after {} seconds", time_diff.count());

        // Return true indicating timeout occurred
        return true;
    }

    // Return false if no timeout occurred
    return false;
}

