bool WebsocketProtocol::Start() {
    // Initialize WebSocket client and set up connection parameters
    // Assuming we have access to WebSocket client implementation
    if (!websocket_client_) {
        websocket_client_ = std::make_unique<WebSocketClient>();

        // Set server address and port from configuration
        auto& ota = Ota::GetInstance();
        std::string server_address = ota.GetWebsocketServerAddress();
        int server_port = ota.GetWebsocketServerPort();

        websocket_client_->SetServerAddress(server_address);
        websocket_client_->SetServerPort(server_port);
    }

    // Configure network interface and establish WiFi connection if needed
    // Using NetworkInterface abstraction for WiFi connectivity
    auto& network_interface = NetworkInterface::GetInstance();
    if (!network_interface.IsConnected()) {
        ESP_LOGI(TAG, "Establishing WiFi connection...");
        if (!network_interface.Connect()) {
            ESP_LOGE(TAG, "Failed to establish WiFi connection");
            SetError("Failed to establish WiFi connection");
            return false;
        }
    }

    // Set up event handlers for WebSocket connection lifecycle events
    // Register websocket event callbacks for connect, disconnect, and error handling
    websocket_client_->OnConnected([this]() {
        ESP_LOGI(TAG, "WebSocket connected to server");
        if (on_connected_) {
            on_connected_();
        }
        // Set up connection parameters after successful connection
        this->session_id_ = websocket_client_->GetSessionId();
        this->server_sample_rate_ = websocket_client_->GetServerSampleRate();
        this->server_frame_duration_ = websocket_client_->GetServerFrameDuration();
    });

    websocket_client_->OnDisconnected([this]() {
        ESP_LOGI(TAG, "WebSocket disconnected from server");
        if (on_disconnected_) {
            on_disconnected_();
        }
    });

    websocket_client_->OnError([this](const std::string& error_message) {
        ESP_LOGE(TAG, "WebSocket error: %s", error_message.c_str());
        SetError(error_message);
        if (on_network_error_) {
            on_network_error_(error_message);
        }
    });

    websocket_client_->OnMessage([this](const std::string& message) {
        // Parse incoming JSON messages
        cJSON* root = cJSON_Parse(message.c_str());
        if (root != nullptr) {
            if (on_incoming_json_) {
                on_incoming_json_(root);
            }
            cJSON_Delete(root);
        } else {
            ESP_LOGW(TAG, "Failed to parse JSON message: %s", message.c_str());
        }
    });

    websocket_client_->OnBinaryMessage([this](const std::vector<uint8_t>& data) {
        // Handle binary audio data
        if (on_incoming_audio_) {
            auto packet = std::make_unique<AudioStreamPacket>();
            // Parse binary protocol header
            if (data.size() >= sizeof(BinaryProtocol3)) {
                const BinaryProtocol3* header = reinterpret_cast<const BinaryProtocol3*>(data.data());
                packet->sample_rate = this->server_sample_rate_;
                packet->frame_duration = this->server_frame_duration_;
                packet->timestamp = 0; // Will be set by caller
                packet->payload.assign(data.begin() + sizeof(BinaryProtocol3), data.end());
                on_incoming_audio_(std::move(packet));
            }
        }
    });

    // Start the WebSocket connection process asynchronously
    // Trigger websocket connect request and return true on successful initiation
    ESP_LOGI(TAG, "Initiating WebSocket connection...");
    if (websocket_client_->Connect()) {
        return true;
    } else {
        ESP_LOGE(TAG, "Failed to initiate WebSocket connection");
        SetError("Failed to initiate WebSocket connection");
        return false;
    }
}

