    cJSON* root = cJSON_CreateObject();

    // Add message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Add protocol version
    cJSON_AddNumberToObject(root, "version", version_);

    // Add features
    cJSON* features = cJSON_CreateArray();
    cJSON_AddItemToArray(features, cJSON_CreateString("aec"));
    cJSON_AddItemToArray(features, cJSON_CreateString("mcp"));
    cJSON_AddItemToObject(root, "features", features);

    // Add transport method
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add audio parameters
    cJSON* audio = cJSON_CreateObject();
    cJSON_AddStringToObject(audio, "format", "pcm");
    cJSON_AddNumberToObject(audio, "sample_rate", 16000);  // Default sample rate
    cJSON_AddNumberToObject(audio, "channels", 1);        // Default channels
    cJSON_AddNumberToObject(audio, "frame_duration", 20); // Default frame duration in ms
    cJSON_AddItemToObject(root, "audio", audio);

    // Convert to string
    char* json_string = cJSON_Print(root);
    std::string result = json_string;

    // Clean up
    cJSON_Free(json_string);
    cJSON_Delete(root);

    return result;
}

bool ParseServerHello(const cJSON *server_hello_json) {
    // Step 1: Parse the JSON object to extract session ID and audio configuration parameters
    const cJSON *session_id_item = cJSON_GetObjectItem(server_hello_json, "session_id");
    const cJSON *audio_config_item = cJSON_GetObjectItem(server_hello_json, "audio_config");
    const cJSON *transport_type_item = cJSON_GetObjectItem(server_hello_json, "transport_type");

    if (!session_id_item || !audio_config_item || !transport_type_item) {
        return false;
    }

    // Extract session ID
    const char *session_id = cJSON_GetStringValue(session_id_item);
    if (!session_id) {
        return false;
    }

    // Validate the transport type specified in the server hello response
    const char *transport_type = cJSON_GetStringValue(transport_type_item);
    if (!transport_type || strcmp(transport_type, "websocket") != 0) {
        return false;
    }

    // Extract audio configuration parameters
    const cJSON *sample_rate_item = cJSON_GetObjectItem(audio_config_item, "sample_rate");
    const cJSON *frame_duration_item = cJSON_GetObjectItem(audio_config_item, "frame_duration");

    if (!sample_rate_item || !frame_duration_item) {
        return false;
    }

    int sample_rate = cJSON_GetNumberValue(sample_rate_item);
    int frame_duration = cJSON_GetNumberValue(frame_duration_item);

    // Set audio configuration parameters like sample rate and frame duration
    // Assuming there are global or member variables to store these values
    // This would typically involve calling setter functions or directly assigning
    SetAudioSampleRate(sample_rate);
    SetAudioFrameDuration(frame_duration);

    // Store session ID (assuming there's a method to store it)
    StoreSessionId(session_id);

    // Signal successful parsing by setting an event flag for further communication
    // This assumes there's an event signaling mechanism available
    SetWebSocketReadyEvent();

    return true;
}
